{
  "name": "Little Bear's Great Adventure",
  "description": "A Nintendo-style side-scrolling platformer where you guide a brave little bear through obstacles, collect coins, and defeat monsters."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  VICTORY = 'VICTORY'
}

export enum EntityType {
  PLAYER = 'PLAYER',
  PLATFORM = 'PLATFORM',
  COIN = 'COIN',
  ENEMY = 'ENEMY',
  SPIKE = 'SPIKE',
  FLAG = 'FLAG',
  LAVA = 'LAVA'
}

export interface Vector {
  x: number;
  y: number;
}

export interface Entity {
  id: string;
  type: EntityType;
  pos: Vector;
  size: Vector;
  vel: Vector;
  color?: string;
  isDead?: boolean;
  patrolStart?: number; // For enemies
  patrolEnd?: number;   // For enemies
}

export interface Player extends Entity {
  isGrounded: boolean;
  facingRight: boolean;
  isInvulnerable: boolean;
  invulnerableTimer: number;
}

export interface LevelData {
  id: number;
  name: string;
  width: number;
  height: number;
  entities: Entity[];
  spawnPoint: Vector;
  backgroundColor: string;
}

export interface GameState {
  status: GameStatus;
  currentLevelId: number;
  score: number;
  lives: number;
  coinsCollected: number;
}

export const CANVAS_WIDTH = 800;
export const CANVAS_HEIGHT = 450;
export const TILE_SIZE = 40;

export const GRAVITY = 0.6;
export const TERMINAL_VELOCITY = 12;
export const MOVE_SPEED = 5;
export const JUMP_FORCE = -14;
export const ENEMY_SPEED = 2;

export const PLAYER_WIDTH = 30;
export const PLAYER_HEIGHT = 30;

export const COLORS = {
  sky: '#87CEEB',
  skyDark: '#1E3A8A', // Night level
  ground: '#4ADE80',
  groundDark: '#14532D',
  dirt: '#854D0E',
  bear: '#92400E', // Brown
  bearFace: '#FCD34D',
  coin: '#FACC15',
  coinShine: '#FEF08A',
  enemy: '#DC2626',
  spike: '#999999',
  lava: '#EF4444',
  lavaSurface: '#FCA5A5',
  flagPole: '#D1D5DB',
  flag: '#DC2626'
};

import { LevelData, EntityType } from './types';
import { CANVAS_HEIGHT, COLORS, TILE_SIZE } from './constants';

const createPlatform = (x: number, y: number, w: number, h: number, id: string) => ({
  id, type: EntityType.PLATFORM, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: h * TILE_SIZE }, vel: { x: 0, y: 0 }
});

const createCoin = (x: number, y: number, id: string) => ({
  id, type: EntityType.COIN, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 10 }, size: { x: 20, y: 20 }, vel: { x: 0, y: 0 }
});

const createEnemy = (x: number, y: number, range: number, id: string) => ({
  id, type: EntityType.ENEMY, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - 30 }, size: { x: 30, y: 30 }, vel: { x: 2, y: 0 }, patrolStart: x * TILE_SIZE, patrolEnd: (x + range) * TILE_SIZE
});

const createSpike = (x: number, y: number, w: number, id: string) => ({
  id, type: EntityType.SPIKE, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: TILE_SIZE / 2 }, vel: { x: 0, y: 0 }
});

const createFlag = (x: number, y: number, id: string) => ({
  id, type: EntityType.FLAG, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - 120 }, size: { x: 40, y: 160 }, vel: { x: 0, y: 0 }
});

