      createPlatform(18, 5, 2, 1, 'step2'),
      createPlatform(22, 3, 2, 1, 'step3'),

      createPlatform(28, 1, 15, 1, 'long-run'),
      createEnemy(30, 1, 10, 'fast-e1'),
      createEnemy(35, 1, 10, 'fast-e2'),

      createPlatform(45, 4, 2, 1, 'tiny1'),
      createPlatform(50, 6, 2, 1, 'tiny2'),
      createPlatform(55, 4, 2, 1, 'tiny3'),
      createPlatform(60, 2, 2, 1, 'tiny4'),

      createPlatform(65, 1, 20, 1, 'final-stretch'),
      createSpike(68, 1, 2, 's1'),
