import React, { useEffect, useRef } from 'react';
import { CANVAS_WIDTH, CANVAS_HEIGHT, GRAVITY, TILE_SIZE, COLORS, PLAYER_WIDTH, PLAYER_HEIGHT, MOVE_SPEED, JUMP_FORCE, TERMINAL_VELOCITY, ENEMY_SPEED } from '../constants';
import { Entity, Player, EntityType, GameStatus, GameState } from '../types';
import { levels } from '../levels';

interface GameCanvasProps {
  levelId: number;
  gameState: GameState;
  setGameState: React.Dispatch<React.SetStateAction<GameState>>;
  onLevelComplete: () => void;
  onGameOver: () => void;
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ levelId, gameState, setGameState, onLevelComplete, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  // Game State Refs (Mutable for performance)
  const levelRef = useRef(levels.find(l => l.id === levelId) || levels[0]);

  const playerRef = useRef<Player>({
    id: 'hero',
    type: EntityType.PLAYER,
    pos: { ...levelRef.current.spawnPoint },
    size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
    vel: { x: 0, y: 0 },
    isGrounded: false,
    facingRight: true,
    isInvulnerable: false,
    invulnerableTimer: 0
  });

  const entitiesRef = useRef<Entity[]>(JSON.parse(JSON.stringify(levelRef.current.entities))); // Deep copy
  const cameraRef = useRef({ x: 0 });
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Reset level when ID changes
  useEffect(() => {
    const newLevel = levels.find(l => l.id === levelId) || levels[0];
    levelRef.current = newLevel;
    entitiesRef.current = JSON.parse(JSON.stringify(newLevel.entities));
    playerRef.current = {
      id: 'hero',
      type: EntityType.PLAYER,
      pos: { ...newLevel.spawnPoint },
      size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
      vel: { x: 0, y: 0 },
      isGrounded: false,
      facingRight: true,
      isInvulnerable: false,
      invulnerableTimer: 0
    };
    cameraRef.current.x = 0;
  }, [levelId]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.code] = false; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Collision Logic
  const checkCollision = (rect1: Entity, rect2: Entity) => {
    return (
      rect1.pos.x < rect2.pos.x + rect2.size.x &&
      rect1.pos.x + rect1.size.x > rect2.pos.x &&
      rect1.pos.y < rect2.pos.y + rect2.size.y &&
      rect1.pos.y + rect1.size.y > rect2.pos.y
    );
  };

  const update = () => {
    if (gameState.status !== GameStatus.PLAYING) return;

    const player = playerRef.current;
    const entities = entitiesRef.current;

    // --- Player Movement ---
    if (keysRef.current['ArrowLeft']) {
      player.vel.x = -MOVE_SPEED;
      player.facingRight = false;
    } else if (keysRef.current['ArrowRight']) {
      player.vel.x = MOVE_SPEED;
      player.facingRight = true;
    } else {
      player.vel.x = 0;
    }

    if ((keysRef.current['Space'] || keysRef.current['ArrowUp']) && player.isGrounded) {
      player.vel.y = JUMP_FORCE;
      player.isGrounded = false;
    }

    // --- Physics ---
    player.vel.y += GRAVITY;
    if (player.vel.y > TERMINAL_VELOCITY) player.vel.y = TERMINAL_VELOCITY;

    // Apply X
    player.pos.x += player.vel.x;

    // X Collisions (Platforms)
    player.isGrounded = false; // Assume falling until proven otherwise

    // Bounds check X
    if (player.pos.x < 0) player.pos.x = 0;
    if (player.pos.x > levelRef.current.width - player.size.x) player.pos.x = levelRef.current.width - player.size.x;

    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          // Resolve X overlap
          if (player.vel.x > 0) { // Moving right
            player.pos.x = ent.pos.x - player.size.x;
          } else if (player.vel.x < 0) { // Moving left
            player.pos.x = ent.pos.x + ent.size.x;
          }
        }
      }
    }

    // Apply Y
    player.pos.y += player.vel.y;

    // Y Collisions (Platforms)
    let landed = false;
    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.y > 0) { // Falling down
            player.pos.y = ent.pos.y - player.size.y;
            player.vel.y = 0;
            landed = true;
          } else if (player.vel.y < 0) { // Jumping up (bonk head)
            player.pos.y = ent.pos.y + ent.size.y;
            player.vel.y = 0;
          }
        }
      }
    }
    player.isGrounded = landed;

    // Death check (Fell off world)
    if (player.pos.y > levelRef.current.height + 100) {
      onGameOver();
      return;
    }

    // --- Interactables ---
    // Invulnerability ticker
    if (player.isInvulnerable) {
      player.invulnerableTimer--;
      if (player.invulnerableTimer <= 0) player.isInvulnerable = false;
    }

    entities.forEach(ent => {
      if (ent.isDead) return;

      // Enemy Patrol Logic
      if (ent.type === EntityType.ENEMY) {
        ent.pos.x += ent.vel.x;
        if (ent.patrolEnd && ent.pos.x >= ent.patrolEnd) ent.vel.x = -Math.abs(ent.vel.x);
        if (ent.patrolStart && ent.pos.x <= ent.patrolStart) ent.vel.x = Math.abs(ent.vel.x);
      }

      // Collisions with Player
      if (checkCollision(player, ent)) {
        if (ent.type === EntityType.COIN) {
          ent.isDead = true;
          setGameState(prev => ({ ...prev, score: prev.score + 100, coinsCollected: prev.coinsCollected + 1 }));
        } else if (ent.type === EntityType.FLAG) {
          onLevelComplete();
        } else if (ent.type === EntityType.SPIKE) {
           if (!player.isInvulnerable) {
              onGameOver();
           }
        } else if (ent.type === EntityType.ENEMY) {
          // Mario style jump kill logic
          // If player is falling and hits the top 50% of the enemy
          const hitFromTop = player.vel.y > 0 && (player.pos.y + player.size.y) < (ent.pos.y + ent.size.y * 0.7);

          if (hitFromTop) {
            ent.isDead = true;
            player.vel.y = JUMP_FORCE / 2; // Bounce
            setGameState(prev => ({ ...prev, score: prev.score + 200 }));
          } else {
             if (!player.isInvulnerable) {
               // Take damage / Die
               // For this simple version, instant death or lives system?
               // Let's do simple lives deduction or restart
               onGameOver();
             }
          }
        }
      }
    });

    // --- Camera Follow ---
    // Keep player in middle third of screen
    const targetCamX = player.pos.x - CANVAS_WIDTH / 3;
    cameraRef.current.x += (targetCamX - cameraRef.current.x) * 0.1; // Smooth lerp

    // Clamp camera
    if (cameraRef.current.x < 0) cameraRef.current.x = 0;
    const maxCamX = levelRef.current.width - CANVAS_WIDTH;
    if (cameraRef.current.x > maxCamX) cameraRef.current.x = maxCamX;
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const cameraX = Math.floor(cameraRef.current.x);
    const player = playerRef.current;

    // Background
    ctx.fillStyle = levelRef.current.backgroundColor;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Clouds (Parallax-ish static for now)
    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.beginPath();
    ctx.arc(100 - cameraX * 0.2, 80, 40, 0, Math.PI * 2);
    ctx.arc(150 - cameraX * 0.2, 90, 50, 0, Math.PI * 2);
    ctx.fill();
    ctx.beginPath();
    ctx.arc(500 - cameraX * 0.2, 60, 60, 0, Math.PI * 2);
    ctx.arc(580 - cameraX * 0.2, 80, 40, 0, Math.PI * 2);
    ctx.fill();

    ctx.save();
    ctx.translate(-cameraX, 0);

    // --- Draw Level Entities ---
    entitiesRef.current.forEach(ent => {
      if (ent.isDead) return;

      if (ent.type === EntityType.PLATFORM) {
        // Top grass
        ctx.fillStyle = COLORS.ground;
        ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
        // Dirt body
        if (ent.size.y > 10) {
           ctx.fillStyle = COLORS.dirt;
           ctx.fillRect(ent.pos.x, ent.pos.y + 10, ent.size.x, ent.size.y - 10);
        }
        // Border
        ctx.strokeStyle = '#14532D';
        ctx.lineWidth = 2;
        ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      } 
      else if (ent.type === EntityType.COIN) {
        ctx.fillStyle = COLORS.coin;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2, ent.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = COLORS.coinShine;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2 - 3, ent.pos.y + ent.size.y/2 - 3, 3, 0, Math.PI * 2);
        ctx.fill();
        // Bobbing animation effect
        ent.pos.y += Math.sin(Date.now() / 200) * 0.2;
      }
      else if (ent.type === EntityType.SPIKE) {
        ctx.fillStyle = COLORS.spike;
        ctx.beginPath();
        const numSpikes = Math.floor(ent.size.x / 10);
        for(let i=0; i<numSpikes; i++) {
            ctx.moveTo(ent.pos.x + i * 10, ent.pos.y + ent.size.y);
            ctx.lineTo(ent.pos.x + i * 10 + 5, ent.pos.y);
            ctx.lineTo(ent.pos.x + i * 10 + 10, ent.pos.y + ent.size.y);
        }
        ctx.fill();
      }
      else if (ent.type === EntityType.ENEMY) {
         ctx.fillStyle = COLORS.enemy;
         ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         // Angry Eyes
         ctx.fillStyle = '#fff';
         ctx.fillRect(ent.pos.x + (ent.vel.x > 0 ? 18 : 4), ent.pos.y + 5, 8, 8);
         ctx.fillStyle = '#000';
         ctx.fillRect(ent.pos.x + (ent.vel.x > 0 ? 20 : 6), ent.pos.y + 7, 4, 4);
         // Eyebrows
         ctx.strokeStyle = '#000';
         ctx.lineWidth = 2;
         ctx.beginPath();
         if (ent.vel.x > 0) {
            ctx.moveTo(ent.pos.x + 18, ent.pos.y + 4);
            ctx.lineTo(ent.pos.x + 26, ent.pos.y + 8);
         } else {
            ctx.moveTo(ent.pos.x + 12, ent.pos.y + 8);
            ctx.lineTo(ent.pos.x + 4, ent.pos.y + 4);
         }
         ctx.stroke();
      }
      else if (ent.type === EntityType.FLAG) {
         ctx.fillStyle = COLORS.flagPole;
         ctx.fillRect(ent.pos.x + 15, ent.pos.y, 5, ent.size.y);
         ctx.fillStyle = COLORS.flag;
         ctx.beginPath();
         ctx.moveTo(ent.pos.x + 20, ent.pos.y + 10);
         ctx.lineTo(ent.pos.x + 55, ent.pos.y + 25);
         ctx.lineTo(ent.pos.x + 20, ent.pos.y + 40);
         ctx.fill();
         // Globe top
         ctx.fillStyle = '#FCD34D';
         ctx.beginPath();
         ctx.arc(ent.pos.x + 17.5, ent.pos.y, 8, 0, Math.PI*2);
         ctx.fill();
      }
    });

    // --- Draw Player (The Bear) ---
    if (player.isInvulnerable && Math.floor(Date.now() / 100) % 2 === 0) {
       // Flicker effect
    } else {
        // Body
        ctx.fillStyle = COLORS.bear;
        ctx.beginPath();
        ctx.roundRect(player.pos.x, player.pos.y, player.size.x, player.size.y, 5);
        ctx.fill();

        // Ears
        ctx.beginPath();
        ctx.arc(player.pos.x + 5, player.pos.y + 2, 6, 0, Math.PI*2); // Left ear
        ctx.arc(player.pos.x + player.size.x - 5, player.pos.y + 2, 6, 0, Math.PI*2); // Right ear
        ctx.fill();

        // Face
        ctx.fillStyle = COLORS.bearFace;
        const faceX = player.facingRight ? player.pos.x + 12 : player.pos.x + 2;
        ctx.beginPath();
        ctx.roundRect(faceX, player.pos.y + 8, 16, 12, 4);
        ctx.fill();

        // Eyes
        ctx.fillStyle = '#000';
        const eyeOffsetX = player.facingRight ? 4 : 0;
        ctx.beginPath();
        ctx.arc(faceX + 4 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
        ctx.arc(faceX + 10 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
        ctx.fill();

        // Nose
        ctx.beginPath();
        ctx.ellipse(faceX + 7 + eyeOffsetX, player.pos.y + 16, 3, 2, 0, 0, Math.PI*2);
        ctx.fill();
    }

    ctx.restore();
  };

  const loop = () => {
    update();
    draw();
    requestRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(loop);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [gameState.status]);

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      className="block bg-black rounded-lg shadow-2xl border-4 border-gray-700 mx-auto"
      style={{ maxWidth: '100%', maxHeight: '80vh', imageRendering: 'pixelated' }}
    />
  );
};

import React, { useState, useEffect } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameStatus, GameState } from './types';
import { levels } from './levels';
import { Heart, Coins, Trophy, skull, Skull } from 'lucide-react'; // Note: lucide-react might not have skull lowercase, corrected below

const INITIAL_STATE: GameState = {
  status: GameStatus.MENU,
  currentLevelId: 1,
  score: 0,
  lives: 3,
  coinsCollected: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(INITIAL_STATE);
  const [highScore, setHighScore] = useState(0);

  useEffect(() => {
    const saved = localStorage.getItem('bear_adventure_highscore');
    if (saved) setHighScore(parseInt(saved));
  }, []);

  useEffect(() => {
    if (gameState.score > highScore) {
      setHighScore(gameState.score);
      localStorage.setItem('bear_adventure_highscore', gameState.score.toString());
    }
  }, [gameState.score, highScore]);

  const startGame = (levelId: number = 1) => {
    setGameState({
      ...INITIAL_STATE,
      status: GameStatus.PLAYING,
      currentLevelId: levelId
    });
  };

  const handleLevelComplete = () => {
    // If last level, win game
    if (gameState.currentLevelId >= levels.length) {
       setGameState(prev => ({ ...prev, status: GameStatus.VICTORY }));
    } else {
       setGameState(prev => ({ ...prev, status: GameStatus.LEVEL_COMPLETE }));
    }
  };

  const handleNextLevel = () => {
    setGameState(prev => ({
      ...prev,
      status: GameStatus.PLAYING,
      currentLevelId: prev.currentLevelId + 1
    }));
  };

  const handleGameOver = () => {
    if (gameState.lives > 1) {
       // Lose a life, restart level
       setGameState(prev => ({
         ...prev,
         lives: prev.lives - 1,
         // We essentially just re-mount the game canvas to reset positions
         // In a complex app we'd have a specific "RESPAWN" state, but toggling PLAYING works here if handled right
       }));
       // Small hack to force reset of level entities: 
       // We need the component to remount or the logic to reset. 
       // The GameCanvas watches 'levelId', but not 'lives'. 
       // Let's toggle a temporary state or rely on key prop.
       // Actually, simply doing nothing here and letting the user click "Retry" on a modal is better UX for "Death".
       // But for "Lost Life" vs "Game Over":
       setGameState(prev => ({ ...prev, status: GameStatus.GAME_OVER })); // Simplified: One mistake = Restart screen for this demo
    } else {
       setGameState(prev => ({ ...prev, status: GameStatus.GAME_OVER }));
    }
  };

  const currentLevel = levels.find(l => l.id === gameState.currentLevelId);

  return (
    <div className="min-h-screen bg-zinc-900 flex flex-col items-center justify-center p-4 font-sans select-none text-white">

      {/* Header / HUD */}
      <div className="w-full max-w-[800px] flex justify-between items-center mb-4 px-4 py-2 bg-zinc-800 rounded-xl border-2 border-zinc-700 shadow-lg">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 text-red-400">
            <Heart className="w-6 h-6 fill-current" />
            <span className="pixel-font text-xl">x {gameState.lives}</span>
          </div>
          <div className="flex items-center gap-2 text-yellow-400">
            <Coins className="w-6 h-6 fill-current" />
            <span className="pixel-font text-xl">{gameState.coinsCollected}</span>
          </div>
        </div>

        <div className="text-center">
            <h1 className="text-sm text-gray-400 uppercase tracking-widest font-bold">{currentLevel?.name || "ADVENTURE"}</h1>
        </div>

        <div className="flex flex-col items-end">
          <span className="text-xs text-gray-400">SCORE</span>
          <span className="pixel-font text-xl text-white">{gameState.score.toString().padStart(6, '0')}</span>
        </div>
      </div>

      {/* Main Game Area */}
      <div className="relative group">

        {/* Render Game Canvas only if Playing (or in background for effect) */}
        <GameCanvas 
          key={gameState.currentLevelId + "-" + gameState.lives + "-" + gameState.status} // Remount on level change or death to reset
          levelId={gameState.currentLevelId}
          gameState={gameState}
          setGameState={setGameState}
          onLevelComplete={handleLevelComplete}
          onGameOver={() => setGameState(prev => ({ ...prev, status: GameStatus.GAME_OVER }))} // Instant game over screen for simplicity
        />

        {/* OVERLAYS */}

        {/* MENU */}
        {gameState.status === GameStatus.MENU && (
          <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center rounded-lg backdrop-blur-sm z-10">
            <h1 className="pixel-font text-5xl text-yellow-400 mb-2 drop-shadow-[0_4px_0_rgba(180,83,9,1)]">
              BEAR ADVENTURE
            </h1>
            <p className="text-gray-300 mb-8 max-w-md">Help Little Bear collect coins and avoid the angry blocks!</p>

            <div className="flex gap-4">
                <button 
                  onClick={() => startGame(1)}
                  className="bg-green-500 hover:bg-green-400 text-white border-b-4 border-green-700 font-bold py-3 px-8 rounded-lg transform active:translate-y-1 active:border-b-0 transition-all pixel-font"
                >
                  START GAME
                </button>
            </div>
            <div className="mt-8 text-sm text-gray-500">
                <p>Controls:</p>
                <div className="flex gap-4 mt-2 justify-center">
                    <span className="bg-zinc-700 px-2 py-1 rounded border border-zinc-600">← Move Left</span>
                    <span className="bg-zinc-700 px-2 py-1 rounded border border-zinc-600">→ Move Right</span>
                    <span className="bg-zinc-700 px-2 py-1 rounded border border-zinc-600">SPACE Jump</span>
                </div>
            </div>
          </div>
        )}

        {/* GAME OVER */}
        {gameState.status === GameStatus.GAME_OVER && (
          <div className="absolute inset-0 bg-red-900/90 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <Skull className="w-16 h-16 text-white mb-4 animate-bounce" />
             <h2 className="pixel-font text-4xl text-white mb-2">GAME OVER</h2>
             <p className="text-white/80 mb-6">You collected {gameState.coinsCollected} coins</p>
             <button 
                  onClick={() => startGame(1)}
                  className="bg-white text-red-900 hover:bg-gray-200 border-b-4 border-gray-400 font-bold py-3 px-8 rounded-lg pixel-font"
                >
                  TRY AGAIN
             </button>
          </div>
        )}

        {/* LEVEL COMPLETE */}
        {gameState.status === GameStatus.LEVEL_COMPLETE && (
          <div className="absolute inset-0 bg-blue-900/90 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <Trophy className="w-16 h-16 text-yellow-400 mb-4 animate-pulse" />
             <h2 className="pixel-font text-4xl text-white mb-2">LEVEL COMPLETE!</h2>
             <p className="text-white/80 mb-6">Get ready for the next challenge...</p>
             <button 
                  onClick={handleNextLevel}
                  className="bg-yellow-400 text-yellow-900 hover:bg-yellow-300 border-b-4 border-yellow-600 font-bold py-3 px-8 rounded-lg pixel-font"
                >
                  NEXT LEVEL
             </button>
          </div>
        )}

        {/* VICTORY */}
        {gameState.status === GameStatus.VICTORY && (
          <div className="absolute inset-0 bg-yellow-500/95 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <div className="text-6xl mb-4">👑</div>
             <h2 className="pixel-font text-5xl text-white mb-4 drop-shadow-md">YOU WON!</h2>
             <p className="text-yellow-900 font-bold text-xl mb-8">
                Little Bear is safe now!
             </p>
             <div className="bg-white/20 p-6 rounded-xl backdrop-blur-md mb-8">
                 <p className="text-yellow-900 font-bold">FINAL SCORE: {gameState.score}</p>
                 <p className="text-yellow-900/80">Coins: {gameState.coinsCollected}</p>
             </div>
             <button 
                  onClick={() => setGameState(INITIAL_STATE)}
                  className="bg-white text-yellow-600 hover:bg-gray-100 border-b-4 border-gray-300 font-bold py-3 px-8 rounded-lg pixel-font"
                >
                  PLAY AGAIN
             </button>
          </div>
        )}

      </div>

      <div className="mt-4 text-gray-500 text-xs">
         High Score: {highScore}
      </div>
    </div>
  );
};

export default App;

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  VICTORY = 'VICTORY',
  REVIVE_PROMPT = 'REVIVE_PROMPT'
}

export enum EntityType {
  PLAYER = 'PLAYER',
  PLATFORM = 'PLATFORM',
  COIN = 'COIN',
  ENEMY = 'ENEMY',
  SPIKE = 'SPIKE',
  FLAG = 'FLAG',
  LAVA = 'LAVA'
}

export interface Vector {
  x: number;
  y: number;
}

export interface Entity {
  id: string;
  type: EntityType;
  pos: Vector;
  size: Vector;
  vel: Vector;
  color?: string;
  isDead?: boolean;
  patrolStart?: number; // For enemies
  patrolEnd?: number;   // For enemies
}

export interface Player extends Entity {
  isGrounded: boolean;
  facingRight: boolean;
  isInvulnerable: boolean;
  invulnerableTimer: number;
}

export interface LevelData {
  id: number;
  name: string;
  width: number;
  height: number;
  entities: Entity[];
  spawnPoint: Vector;
  backgroundColor: string;
}

export interface GameState {
  status: GameStatus;
  currentLevelId: number;
  score: number;
  lives: number;
  coinsCollected: number;
}

export const CANVAS_WIDTH = 800;
export const CANVAS_HEIGHT = 450;
export const TILE_SIZE = 40;

export const GRAVITY = 0.6;
export const TERMINAL_VELOCITY = 12;
export const MOVE_SPEED = 5;
export const JUMP_FORCE = -14;
export const ENEMY_SPEED = 2;

export const PLAYER_WIDTH = 30;
export const PLAYER_HEIGHT = 30;

export const MAX_HEALTH = 3;
export const REVIVE_COST = 50;

export const COLORS = {
  sky: '#87CEEB',
  skyDark: '#1E3A8A', // Night level
  ground: '#4ADE80',
  groundDark: '#14532D',
  dirt: '#854D0E',
  bear: '#92400E', // Brown
  bearFace: '#FCD34D',
  coin: '#FACC15',
  coinShine: '#FEF08A',
  enemy: '#DC2626',
  spike: '#999999',
  lava: '#EF4444',
  lavaSurface: '#FCA5A5',
  flagPole: '#D1D5DB',
  flag: '#DC2626'
};

import React, { useEffect, useRef } from 'react';
import { CANVAS_WIDTH, CANVAS_HEIGHT, GRAVITY, TILE_SIZE, COLORS, PLAYER_WIDTH, PLAYER_HEIGHT, MOVE_SPEED, JUMP_FORCE, TERMINAL_VELOCITY } from '../constants';
import { Entity, Player, EntityType, GameStatus, GameState } from '../types';
import { levels } from '../levels';

interface GameCanvasProps {
  levelId: number;
  gameState: GameState;
  setGameState: React.Dispatch<React.SetStateAction<GameState>>;
  onLevelComplete: () => void;
  onPlayerHit: () => void; // Replaces direct onGameOver for non-fatal hits
  onGameOver: () => void; // For falling off map
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ levelId, gameState, setGameState, onLevelComplete, onPlayerHit, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  // Game State Refs (Mutable for performance)
  const levelRef = useRef(levels.find(l => l.id === levelId) || levels[0]);

  const playerRef = useRef<Player>({
    id: 'hero',
    type: EntityType.PLAYER,
    pos: { ...levelRef.current.spawnPoint },
    size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
    vel: { x: 0, y: 0 },
    isGrounded: false,
    facingRight: true,
    isInvulnerable: false,
    invulnerableTimer: 0
  });

  const entitiesRef = useRef<Entity[]>(JSON.parse(JSON.stringify(levelRef.current.entities))); // Deep copy
  const cameraRef = useRef({ x: 0 });
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Reset level when ID changes
  useEffect(() => {
    const newLevel = levels.find(l => l.id === levelId) || levels[0];
    levelRef.current = newLevel;
    entitiesRef.current = JSON.parse(JSON.stringify(newLevel.entities));
    playerRef.current = {
      id: 'hero',
      type: EntityType.PLAYER,
      pos: { ...newLevel.spawnPoint },
      size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
      vel: { x: 0, y: 0 },
      isGrounded: false,
      facingRight: true,
      isInvulnerable: false,
      invulnerableTimer: 0
    };
    cameraRef.current.x = 0;
  }, [levelId]);

  // Handle "Respawn" when falling into pit, OR general reset if requested
  // However, for "Revive on Spot", we rely on the fact that this component DOES NOT unmount/remount
  // and we only reset if levelId changes.

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.code] = false; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Collision Logic
  const checkCollision = (rect1: Entity, rect2: Entity) => {
    return (
      rect1.pos.x < rect2.pos.x + rect2.size.x &&
      rect1.pos.x + rect1.size.x > rect2.pos.x &&
      rect1.pos.y < rect2.pos.y + rect2.size.y &&
      rect1.pos.y + rect1.size.y > rect2.pos.y
    );
  };

  const update = () => {
    // ONLY update physics if we are strictly playing. 
    // This effectively "pauses" the game when status is REVIVE_PROMPT
    if (gameState.status !== GameStatus.PLAYING) return;

    const player = playerRef.current;
    const entities = entitiesRef.current;

    // --- Player Movement ---
    if (keysRef.current['ArrowLeft']) {
      player.vel.x = -MOVE_SPEED;
      player.facingRight = false;
    } else if (keysRef.current['ArrowRight']) {
      player.vel.x = MOVE_SPEED;
      player.facingRight = true;
    } else {
      player.vel.x = 0;
    }

    if ((keysRef.current['Space'] || keysRef.current['ArrowUp']) && player.isGrounded) {
      player.vel.y = JUMP_FORCE;
      player.isGrounded = false;
    }

    // --- Physics ---
    player.vel.y += GRAVITY;
    if (player.vel.y > TERMINAL_VELOCITY) player.vel.y = TERMINAL_VELOCITY;

    // Apply X
    player.pos.x += player.vel.x;

    // X Collisions (Platforms)
    player.isGrounded = false; // Assume falling until proven otherwise

    // Bounds check X
    if (player.pos.x < 0) player.pos.x = 0;
    if (player.pos.x > levelRef.current.width - player.size.x) player.pos.x = levelRef.current.width - player.size.x;

    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          // Resolve X overlap
          if (player.vel.x > 0) { // Moving right
            player.pos.x = ent.pos.x - player.size.x;
          } else if (player.vel.x < 0) { // Moving left
            player.pos.x = ent.pos.x + ent.size.x;
          }
        }
      }
    }

    // Apply Y
    player.pos.y += player.vel.y;

    // Y Collisions (Platforms)
    let landed = false;
    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.y > 0) { // Falling down
            player.pos.y = ent.pos.y - player.size.y;
            player.vel.y = 0;
            landed = true;
          } else if (player.vel.y < 0) { // Jumping up (bonk head)
            player.pos.y = ent.pos.y + ent.size.y;
            player.vel.y = 0;
          }
        }
      }
    }
    player.isGrounded = landed;

    // Death check (Fell off world)
    if (player.pos.y > levelRef.current.height + 100) {
      onGameOver(); // This is typically fatal, triggers restart
      return;
    }

    // --- Interactables ---
    // Invulnerability ticker
    if (player.isInvulnerable) {
      player.invulnerableTimer--;
      if (player.invulnerableTimer <= 0) player.isInvulnerable = false;
    }

    entities.forEach(ent => {
      if (ent.isDead) return;

      // Enemy Patrol Logic
      if (ent.type === EntityType.ENEMY) {
        ent.pos.x += ent.vel.x;
        if (ent.patrolEnd && ent.pos.x >= ent.patrolEnd) ent.vel.x = -Math.abs(ent.vel.x);
        if (ent.patrolStart && ent.pos.x <= ent.patrolStart) ent.vel.x = Math.abs(ent.vel.x);
      }

      // Collisions with Player
      if (checkCollision(player, ent)) {
        if (ent.type === EntityType.COIN) {
          ent.isDead = true;
          setGameState(prev => ({ ...prev, score: prev.score + 100, coinsCollected: prev.coinsCollected + 1 }));
        } else if (ent.type === EntityType.FLAG) {
          onLevelComplete();
        } else if (ent.type === EntityType.SPIKE) {
           if (!player.isInvulnerable) {
              handleDamage(player);
           }
        } else if (ent.type === EntityType.ENEMY) {
          // Mario style jump kill logic
          const hitFromTop = player.vel.y > 0 && (player.pos.y + player.size.y) < (ent.pos.y + ent.size.y * 0.7);

          if (hitFromTop) {
            ent.isDead = true;
            player.vel.y = JUMP_FORCE / 2; // Bounce
            setGameState(prev => ({ ...prev, score: prev.score + 200 }));
          } else {
             if (!player.isInvulnerable) {
               handleDamage(player);
             }
          }
        }
      }
    });

    // --- Camera Follow ---
    const targetCamX = player.pos.x - CANVAS_WIDTH / 3;
    cameraRef.current.x += (targetCamX - cameraRef.current.x) * 0.1;
    if (cameraRef.current.x < 0) cameraRef.current.x = 0;
    const maxCamX = levelRef.current.width - CANVAS_WIDTH;
    if (cameraRef.current.x > maxCamX) cameraRef.current.x = maxCamX;
  };

  const handleDamage = (player: Player) => {
    player.isInvulnerable = true;
    player.invulnerableTimer = 120; // 2 seconds at 60fps

    // Knockback
    player.vel.y = -6;
    player.vel.x = player.facingRight ? -4 : 4;

    onPlayerHit();
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const cameraX = Math.floor(cameraRef.current.x);
    const player = playerRef.current;

    // Background
    ctx.fillStyle = levelRef.current.backgroundColor;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Clouds
    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.beginPath();
    ctx.arc(100 - cameraX * 0.2, 80, 40, 0, Math.PI * 2);
    ctx.arc(150 - cameraX * 0.2, 90, 50, 0, Math.PI * 2);
    ctx.fill();
    ctx.beginPath();
    ctx.arc(500 - cameraX * 0.2, 60, 60, 0, Math.PI * 2);
    ctx.arc(580 - cameraX * 0.2, 80, 40, 0, Math.PI * 2);
    ctx.fill();

    ctx.save();
    ctx.translate(-cameraX, 0);

    // --- Draw Level Entities ---
    entitiesRef.current.forEach(ent => {
      if (ent.isDead) return;

      if (ent.type === EntityType.PLATFORM) {
        ctx.fillStyle = COLORS.ground;
        ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
        if (ent.size.y > 10) {
           ctx.fillStyle = COLORS.dirt;
           ctx.fillRect(ent.pos.x, ent.pos.y + 10, ent.size.x, ent.size.y - 10);
        }
        ctx.strokeStyle = '#14532D';
        ctx.lineWidth = 2;
        ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      } 
      else if (ent.type === EntityType.COIN) {
        ctx.fillStyle = COLORS.coin;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2, ent.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = COLORS.coinShine;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2 - 3, ent.pos.y + ent.size.y/2 - 3, 3, 0, Math.PI * 2);
        ctx.fill();
        ent.pos.y += Math.sin(Date.now() / 200) * 0.2;
      }
      else if (ent.type === EntityType.SPIKE) {
        ctx.fillStyle = COLORS.spike;
        ctx.beginPath();
        const numSpikes = Math.floor(ent.size.x / 10);
        for(let i=0; i<numSpikes; i++) {
            ctx.moveTo(ent.pos.x + i * 10, ent.pos.y + ent.size.y);
            ctx.lineTo(ent.pos.x + i * 10 + 5, ent.pos.y);
            ctx.lineTo(ent.pos.x + i * 10 + 10, ent.pos.y + ent.size.y);
        }
        ctx.fill();
      }
      else if (ent.type === EntityType.ENEMY) {
         ctx.fillStyle = COLORS.enemy;
         ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         ctx.fillStyle = '#fff';
         ctx.fillRect(ent.pos.x + (ent.vel.x > 0 ? 18 : 4), ent.pos.y + 5, 8, 8);
         ctx.fillStyle = '#000';
         ctx.fillRect(ent.pos.x + (ent.vel.x > 0 ? 20 : 6), ent.pos.y + 7, 4, 4);
         ctx.strokeStyle = '#000';
         ctx.lineWidth = 2;
         ctx.beginPath();
         if (ent.vel.x > 0) {
            ctx.moveTo(ent.pos.x + 18, ent.pos.y + 4);
            ctx.lineTo(ent.pos.x + 26, ent.pos.y + 8);
         } else {
            ctx.moveTo(ent.pos.x + 12, ent.pos.y + 8);
            ctx.lineTo(ent.pos.x + 4, ent.pos.y + 4);
         }
         ctx.stroke();
      }
      else if (ent.type === EntityType.FLAG) {
         ctx.fillStyle = COLORS.flagPole;
         ctx.fillRect(ent.pos.x + 15, ent.pos.y, 5, ent.size.y);
         ctx.fillStyle = COLORS.flag;
         ctx.beginPath();
         ctx.moveTo(ent.pos.x + 20, ent.pos.y + 10);
         ctx.lineTo(ent.pos.x + 55, ent.pos.y + 25);
         ctx.lineTo(ent.pos.x + 20, ent.pos.y + 40);
         ctx.fill();
         ctx.fillStyle = '#FCD34D';
         ctx.beginPath();
         ctx.arc(ent.pos.x + 17.5, ent.pos.y, 8, 0, Math.PI*2);
         ctx.fill();
      }
    });

    // --- Draw Player (The Bear) ---
    // Flash if invulnerable
    if (player.isInvulnerable && Math.floor(Date.now() / 100) % 2 === 0) {
       ctx.globalAlpha = 0.5;
    }

    ctx.fillStyle = COLORS.bear;
    ctx.beginPath();
    ctx.roundRect(player.pos.x, player.pos.y, player.size.x, player.size.y, 5);
    ctx.fill();

    ctx.beginPath();
    ctx.arc(player.pos.x + 5, player.pos.y + 2, 6, 0, Math.PI*2); // Left ear
    ctx.arc(player.pos.x + player.size.x - 5, player.pos.y + 2, 6, 0, Math.PI*2); // Right ear
    ctx.fill();

    ctx.fillStyle = COLORS.bearFace;
    const faceX = player.facingRight ? player.pos.x + 12 : player.pos.x + 2;
    ctx.beginPath();
    ctx.roundRect(faceX, player.pos.y + 8, 16, 12, 4);
    ctx.fill();

    ctx.fillStyle = '#000';
    const eyeOffsetX = player.facingRight ? 4 : 0;
    ctx.beginPath();
    ctx.arc(faceX + 4 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.arc(faceX + 10 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.fill();

    ctx.beginPath();
    ctx.ellipse(faceX + 7 + eyeOffsetX, player.pos.y + 16, 3, 2, 0, 0, Math.PI*2);
    ctx.fill();

    ctx.globalAlpha = 1.0;
    ctx.restore();
  };

  const loop = () => {
    update();
    draw();
    requestRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(loop);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [gameState.status]);

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      className="block bg-black rounded-lg shadow-2xl border-4 border-gray-700 mx-auto"
      style={{ maxWidth: '100%', maxHeight: '80vh', imageRendering: 'pixelated' }}
    />
  );
};

import React, { useState, useEffect } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameStatus, GameState } from './types';
import { levels } from './levels';
import { Heart, Coins, Trophy, Skull } from 'lucide-react';
import { MAX_HEALTH, REVIVE_COST } from './constants';

const INITIAL_STATE: GameState = {
  status: GameStatus.MENU,
  currentLevelId: 1,
  score: 0,
  lives: MAX_HEALTH, // Acts as HP now
  coinsCollected: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(INITIAL_STATE);
  const [highScore, setHighScore] = useState(0);

  useEffect(() => {
