import React, { useEffect, useRef } from 'react';
import { CANVAS_WIDTH, CANVAS_HEIGHT, GRAVITY, TILE_SIZE, COLORS, PLAYER_WIDTH, PLAYER_HEIGHT, MOVE_SPEED, JUMP_FORCE, TERMINAL_VELOCITY } from '../constants';
import { Entity, Player, EntityType, GameStatus, GameState } from '../types';
import { levels } from '../levels';

interface GameCanvasProps {
  levelId: number;
  gameState: GameState;
  setGameState: React.Dispatch<React.SetStateAction<GameState>>;
  onLevelComplete: () => void;
  onPlayerHit: () => void; // Replaces direct onGameOver for non-fatal hits
  onGameOver: () => void; // For falling off map
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ levelId, gameState, setGameState, onLevelComplete, onPlayerHit, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  // Game State Refs (Mutable for performance)
  const levelRef = useRef(levels.find(l => l.id === levelId) || levels[0]);

  const playerRef = useRef<Player>({
    id: 'hero',
    type: EntityType.PLAYER,
    pos: { ...levelRef.current.spawnPoint },
    size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
    vel: { x: 0, y: 0 },
    isGrounded: false,
    facingRight: true,
    isInvulnerable: false,
    invulnerableTimer: 0
  });

  const entitiesRef = useRef<Entity[]>(JSON.parse(JSON.stringify(levelRef.current.entities))); // Deep copy
  const cameraRef = useRef({ x: 0 });
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Reset level when ID changes
  useEffect(() => {
    const newLevel = levels.find(l => l.id === levelId) || levels[0];
    levelRef.current = newLevel;
    entitiesRef.current = JSON.parse(JSON.stringify(newLevel.entities));
    playerRef.current = {
      id: 'hero',
      type: EntityType.PLAYER,
      pos: { ...newLevel.spawnPoint },
      size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
      vel: { x: 0, y: 0 },
      isGrounded: false,
      facingRight: true,
      isInvulnerable: false,
      invulnerableTimer: 0
    };
    cameraRef.current.x = 0;
  }, [levelId]);

  // Handle "Rescue" when resuming game if player is in a bad spot (e.g. fell off map but revived)
  useEffect(() => {
    if (gameState.status === GameStatus.PLAYING) {
       // If player is way below map (fell off), reset them to spawn point when resuming
       if (playerRef.current.pos.y > levelRef.current.height + 50) {
           playerRef.current.pos = { ...levelRef.current.spawnPoint };
           playerRef.current.vel = { x: 0, y: 0 };
           // We keep camera as is, or maybe lerp it back? 
           // For simplicity, let update() handle camera catch-up or snap it:
           cameraRef.current.x = Math.max(0, playerRef.current.pos.x - CANVAS_WIDTH / 3);
       }
       // Clear keys to prevent stuck inputs
       keysRef.current = {}; 
    }
  }, [gameState.status]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.code] = false; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Collision Logic
  const checkCollision = (rect1: Entity, rect2: Entity) => {
    return (
      rect1.pos.x < rect2.pos.x + rect2.size.x &&
      rect1.pos.x + rect1.size.x > rect2.pos.x &&
      rect1.pos.y < rect2.pos.y + rect2.size.y &&
      rect1.pos.y + rect1.size.y > rect2.pos.y
    );
  };

  const update = () => {
    // ONLY update physics if we are strictly playing. 
    // This effectively "pauses" the game when status is REVIVE_PROMPT
    if (gameState.status !== GameStatus.PLAYING) return;

    const player = playerRef.current;
    const entities = entitiesRef.current;

    // --- Player Movement ---
    if (keysRef.current['ArrowLeft']) {
      player.vel.x = -MOVE_SPEED;
      player.facingRight = false;
    } else if (keysRef.current['ArrowRight']) {
      player.vel.x = MOVE_SPEED;
      player.facingRight = true;
    } else {
      player.vel.x = 0;
    }

    if ((keysRef.current['Space'] || keysRef.current['ArrowUp']) && player.isGrounded) {
      player.vel.y = JUMP_FORCE;
      player.isGrounded = false;
    }

    // --- Physics ---
    player.vel.y += GRAVITY;
    if (player.vel.y > TERMINAL_VELOCITY) player.vel.y = TERMINAL_VELOCITY;

    // Apply X
    player.pos.x += player.vel.x;

    // X Collisions (Platforms)
    player.isGrounded = false; // Assume falling until proven otherwise

    // Bounds check X
    if (player.pos.x < 0) player.pos.x = 0;
    if (player.pos.x > levelRef.current.width - player.size.x) player.pos.x = levelRef.current.width - player.size.x;

    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          // Resolve X overlap
          if (player.vel.x > 0) { // Moving right
            player.pos.x = ent.pos.x - player.size.x;
          } else if (player.vel.x < 0) { // Moving left
            player.pos.x = ent.pos.x + ent.size.x;
          }
        }
      }
    }

    // Apply Y
    player.pos.y += player.vel.y;

    // Y Collisions (Platforms)
    let landed = false;
    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.y > 0) { // Falling down
            player.pos.y = ent.pos.y - player.size.y;
            player.vel.y = 0;
            landed = true;
          } else if (player.vel.y < 0) { // Jumping up (bonk head)
            player.pos.y = ent.pos.y + ent.size.y;
            player.vel.y = 0;
          }
        }
      }
    }
    player.isGrounded = landed;

    // Death check (Fell off world)
    if (player.pos.y > levelRef.current.height + 100) {
      onGameOver(); // This is typically fatal, triggers restart
      return;
    }

    // --- Interactables ---
    // Invulnerability ticker
    if (player.isInvulnerable) {
      player.invulnerableTimer--;
      if (player.invulnerableTimer <= 0) player.isInvulnerable = false;
    }

    entities.forEach(ent => {
      if (ent.isDead) return;

      // Enemy Patrol Logic
      if (ent.type === EntityType.ENEMY) {
        ent.pos.x += ent.vel.x;
        if (ent.patrolEnd && ent.pos.x >= ent.patrolEnd) ent.vel.x = -Math.abs(ent.vel.x);
        if (ent.patrolStart && ent.pos.x <= ent.patrolStart) ent.vel.x = Math.abs(ent.vel.x);
      }

      // Collisions with Player
      if (checkCollision(player, ent)) {
        if (ent.type === EntityType.COIN) {
          ent.isDead = true;
          setGameState(prev => ({ ...prev, score: prev.score + 100, coinsCollected: prev.coinsCollected + 1 }));
        } else if (ent.type === EntityType.FLAG) {
          onLevelComplete();
        } else if (ent.type === EntityType.SPIKE) {
           if (!player.isInvulnerable) {
              handleDamage(player);
           }
        } else if (ent.type === EntityType.ENEMY) {
          // Mario style jump kill logic
          const hitFromTop = player.vel.y > 0 && (player.pos.y + player.size.y) < (ent.pos.y + ent.size.y * 0.7);

          if (hitFromTop) {
            ent.isDead = true;
            player.vel.y = JUMP_FORCE / 2; // Bounce
            setGameState(prev => ({ ...prev, score: prev.score + 200 }));
          } else {
             if (!player.isInvulnerable) {
               handleDamage(player);
             }
          }
        }
      }
    });

    // --- Camera Follow ---
    const targetCamX = player.pos.x - CANVAS_WIDTH / 3;
    cameraRef.current.x += (targetCamX - cameraRef.current.x) * 0.1;
    if (cameraRef.current.x < 0) cameraRef.current.x = 0;
    const maxCamX = levelRef.current.width - CANVAS_WIDTH;
    if (cameraRef.current.x > maxCamX) cameraRef.current.x = maxCamX;
  };

  const handleDamage = (player: Player) => {
    player.isInvulnerable = true;
    player.invulnerableTimer = 120; // 2 seconds at 60fps

    // Knockback
    player.vel.y = -6;
    player.vel.x = player.facingRight ? -4 : 4;

    onPlayerHit();
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const cameraX = Math.floor(cameraRef.current.x);
    const player = playerRef.current;

    // Background
    ctx.fillStyle = levelRef.current.backgroundColor;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Clouds
    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.beginPath();
    ctx.arc(100 - cameraX * 0.2, 80, 40, 0, Math.PI * 2);
    ctx.arc(150 - cameraX * 0.2, 90, 50, 0, Math.PI * 2);
    ctx.fill();
    ctx.beginPath();
    ctx.arc(500 - cameraX * 0.2, 60, 60, 0, Math.PI * 2);
    ctx.arc(580 - cameraX * 0.2, 80, 40, 0, Math.PI * 2);
    ctx.fill();

    ctx.save();
    ctx.translate(-cameraX, 0);

    // --- Draw Level Entities ---
    entitiesRef.current.forEach(ent => {
      if (ent.isDead) return;

      if (ent.type === EntityType.PLATFORM) {
        ctx.fillStyle = COLORS.ground;
        ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
        if (ent.size.y > 10) {
           ctx.fillStyle = COLORS.dirt;
           ctx.fillRect(ent.pos.x, ent.pos.y + 10, ent.size.x, ent.size.y - 10);
        }
        ctx.strokeStyle = '#14532D';
        ctx.lineWidth = 2;
        ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      } 
      else if (ent.type === EntityType.COIN) {
        ctx.fillStyle = COLORS.coin;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2, ent.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = COLORS.coinShine;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2 - 3, ent.pos.y + ent.size.y/2 - 3, 3, 0, Math.PI * 2);
        ctx.fill();
        ent.pos.y += Math.sin(Date.now() / 200) * 0.2;
      }
      else if (ent.type === EntityType.SPIKE) {
        ctx.fillStyle = COLORS.spike;
        ctx.beginPath();
        const numSpikes = Math.floor(ent.size.x / 10);
        for(let i=0; i<numSpikes; i++) {
            ctx.moveTo(ent.pos.x + i * 10, ent.pos.y + ent.size.y);
            ctx.lineTo(ent.pos.x + i * 10 + 5, ent.pos.y);
            ctx.lineTo(ent.pos.x + i * 10 + 10, ent.pos.y + ent.size.y);
        }
        ctx.fill();
      }
      else if (ent.type === EntityType.ENEMY) {
         ctx.fillStyle = COLORS.enemy;
         ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         ctx.fillStyle = '#fff';
         ctx.fillRect(ent.pos.x + (ent.vel.x > 0 ? 18 : 4), ent.pos.y + 5, 8, 8);
         ctx.fillStyle = '#000';
         ctx.fillRect(ent.pos.x + (ent.vel.x > 0 ? 20 : 6), ent.pos.y + 7, 4, 4);
         ctx.strokeStyle = '#000';
         ctx.lineWidth = 2;
         ctx.beginPath();
         if (ent.vel.x > 0) {
            ctx.moveTo(ent.pos.x + 18, ent.pos.y + 4);
            ctx.lineTo(ent.pos.x + 26, ent.pos.y + 8);
         } else {
            ctx.moveTo(ent.pos.x + 12, ent.pos.y + 8);
            ctx.lineTo(ent.pos.x + 4, ent.pos.y + 4);
         }
         ctx.stroke();
      }
      else if (ent.type === EntityType.FLAG) {
         ctx.fillStyle = COLORS.flagPole;
         ctx.fillRect(ent.pos.x + 15, ent.pos.y, 5, ent.size.y);
         ctx.fillStyle = COLORS.flag;
         ctx.beginPath();
         ctx.moveTo(ent.pos.x + 20, ent.pos.y + 10);
         ctx.lineTo(ent.pos.x + 55, ent.pos.y + 25);
         ctx.lineTo(ent.pos.x + 20, ent.pos.y + 40);
         ctx.fill();
         ctx.fillStyle = '#FCD34D';
         ctx.beginPath();
         ctx.arc(ent.pos.x + 17.5, ent.pos.y, 8, 0, Math.PI*2);
         ctx.fill();
      }
    });

    // --- Draw Player (The Bear) ---
    // Flash if invulnerable
    if (player.isInvulnerable && Math.floor(Date.now() / 100) % 2 === 0) {
       ctx.globalAlpha = 0.5;
    }

    ctx.fillStyle = COLORS.bear;
    ctx.beginPath();
    ctx.roundRect(player.pos.x, player.pos.y, player.size.x, player.size.y, 5);
    ctx.fill();

    ctx.beginPath();
    ctx.arc(player.pos.x + 5, player.pos.y + 2, 6, 0, Math.PI*2); // Left ear
    ctx.arc(player.pos.x + player.size.x - 5, player.pos.y + 2, 6, 0, Math.PI*2); // Right ear
    ctx.fill();

    ctx.fillStyle = COLORS.bearFace;
    const faceX = player.facingRight ? player.pos.x + 12 : player.pos.x + 2;
    ctx.beginPath();
    ctx.roundRect(faceX, player.pos.y + 8, 16, 12, 4);
    ctx.fill();

    ctx.fillStyle = '#000';
    const eyeOffsetX = player.facingRight ? 4 : 0;
    ctx.beginPath();
    ctx.arc(faceX + 4 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.arc(faceX + 10 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.fill();

    ctx.beginPath();
    ctx.ellipse(faceX + 7 + eyeOffsetX, player.pos.y + 16, 3, 2, 0, 0, Math.PI*2);
    ctx.fill();

    ctx.globalAlpha = 1.0;
    ctx.restore();
  };

  const loop = () => {
    update();
    draw();
    requestRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(loop);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [gameState.status]);

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      className="block bg-black rounded-lg shadow-2xl border-4 border-gray-700 mx-auto"
      style={{ maxWidth: '100%', maxHeight: '80vh', imageRendering: 'pixelated' }}
    />
  );
};

export const CANVAS_WIDTH = 800;
export const CANVAS_HEIGHT = 450;
export const TILE_SIZE = 40;

export const GRAVITY = 0.6;
export const TERMINAL_VELOCITY = 12;
export const MOVE_SPEED = 5;
export const JUMP_FORCE = -14;
export const ENEMY_SPEED = 2;

export const PLAYER_WIDTH = 30;
export const PLAYER_HEIGHT = 30;

export const MAX_HEALTH = 3;
export const REVIVE_COST = 1; // Changed from 50 to 1

export const COLORS = {
  sky: '#87CEEB',
  skyDark: '#1E3A8A', // Night level
  ground: '#4ADE80',
  groundDark: '#14532D',
  dirt: '#854D0E',
  bear: '#92400E', // Brown
  bearFace: '#FCD34D',
  coin: '#FACC15',
  coinShine: '#FEF08A',
  enemy: '#DC2626',
  spike: '#999999',
  lava: '#EF4444',
  lavaSurface: '#FCA5A5',
  flagPole: '#D1D5DB',
  flag: '#DC2626',
  gateDark: '#374151',
  gateLight: '#9CA3AF'
};

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  VICTORY = 'VICTORY',
  REVIVE_PROMPT = 'REVIVE_PROMPT'
}

export enum EntityType {
  PLAYER = 'PLAYER',
  PLATFORM = 'PLATFORM',
  COIN = 'COIN',
  ENEMY = 'ENEMY',
  SPIKE = 'SPIKE',
  FLAG = 'FLAG', // Now represents the Gate/Door
  LAVA = 'LAVA'
}

export type WeatherType = 'SUNNY' | 'RAIN' | 'SNOW';

export interface Vector {
  x: number;
  y: number;
}

export interface Entity {
  id: string;
  type: EntityType;
  pos: Vector;
  size: Vector;
  vel: Vector;
  color?: string;
  isDead?: boolean;
  patrolStart?: number; // For enemies
  patrolEnd?: number;   // For enemies
}

export interface Player extends Entity {
  isGrounded: boolean;
  facingRight: boolean;
  isInvulnerable: boolean;
  invulnerableTimer: number;
}

export interface LevelData {
  id: number;
  name: string;
  width: number;
  height: number;
  entities: Entity[];
  spawnPoint: Vector;
  backgroundColor: string;
  weather: WeatherType;
}

export interface GameState {
  status: GameStatus;
  currentLevelId: number;
  score: number;
  lives: number;
  coinsCollected: number;
}

import React, { useEffect, useRef } from 'react';
import { CANVAS_WIDTH, CANVAS_HEIGHT, GRAVITY, TILE_SIZE, COLORS, PLAYER_WIDTH, PLAYER_HEIGHT, MOVE_SPEED, JUMP_FORCE, TERMINAL_VELOCITY } from '../constants';
import { Entity, Player, EntityType, GameStatus, GameState, WeatherType } from '../types';
import { levels } from '../levels';

interface GameCanvasProps {
  levelId: number;
  gameState: GameState;
  setGameState: React.Dispatch<React.SetStateAction<GameState>>;
  onLevelComplete: () => void;
  onPlayerHit: () => void;
  onGameOver: () => void;
}

interface Cloud {
  x: number;
  y: number;
  speed: number;
  size: number;
}

interface Particle {
  x: number;
  y: number;
  speedX: number;
  speedY: number;
  size: number;
  life: number;
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ levelId, gameState, setGameState, onLevelComplete, onPlayerHit, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  // Game State Refs
  const levelRef = useRef(levels.find(l => l.id === levelId) || levels[0]);

  const playerRef = useRef<Player>({
    id: 'hero',
    type: EntityType.PLAYER,
    pos: { ...levelRef.current.spawnPoint },
    size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
    vel: { x: 0, y: 0 },
    isGrounded: false,
    facingRight: true,
    isInvulnerable: false,
    invulnerableTimer: 0
  });

  const entitiesRef = useRef<Entity[]>(JSON.parse(JSON.stringify(levelRef.current.entities)));
  const cameraRef = useRef({ x: 0 });
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Environment Refs
  const cloudsRef = useRef<Cloud[]>([]);
  const particlesRef = useRef<Particle[]>([]);

  // Init Clouds
  useEffect(() => {
    cloudsRef.current = Array.from({ length: 8 }).map(() => ({
      x: Math.random() * CANVAS_WIDTH * 2,
      y: Math.random() * (CANVAS_HEIGHT / 2),
      speed: 0.2 + Math.random() * 0.5,
      size: 30 + Math.random() * 40
    }));
  }, []);

  // Reset level when ID changes
  useEffect(() => {
    const newLevel = levels.find(l => l.id === levelId) || levels[0];
    levelRef.current = newLevel;
    entitiesRef.current = JSON.parse(JSON.stringify(newLevel.entities));
    playerRef.current = {
      id: 'hero',
      type: EntityType.PLAYER,
      pos: { ...newLevel.spawnPoint },
      size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
      vel: { x: 0, y: 0 },
      isGrounded: false,
      facingRight: true,
      isInvulnerable: false,
      invulnerableTimer: 0
    };
    cameraRef.current.x = 0;
    particlesRef.current = []; // Clear weather particles
  }, [levelId]);

  // Handle "Rescue"
  useEffect(() => {
    if (gameState.status === GameStatus.PLAYING) {
       if (playerRef.current.pos.y > levelRef.current.height + 50) {
           playerRef.current.pos = { ...levelRef.current.spawnPoint };
           playerRef.current.vel = { x: 0, y: 0 };
           cameraRef.current.x = Math.max(0, playerRef.current.pos.x - CANVAS_WIDTH / 3);
       }
       keysRef.current = {}; 
    }
  }, [gameState.status]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.code] = false; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const checkCollision = (rect1: Entity, rect2: Entity) => {
    return (
      rect1.pos.x < rect2.pos.x + rect2.size.x &&
      rect1.pos.x + rect1.size.x > rect2.pos.x &&
      rect1.pos.y < rect2.pos.y + rect2.size.y &&
      rect1.pos.y + rect1.size.y > rect2.pos.y
    );
  };

  const updateEnvironment = () => {
    // 1. Move Clouds (Always move regardless of game status)
    cloudsRef.current.forEach(cloud => {
      cloud.x -= cloud.speed;
      // Loop cloud
      if (cloud.x + cloud.size * 2 < 0) {
         cloud.x = CANVAS_WIDTH * 2 + Math.random() * 200;
         cloud.y = Math.random() * (CANVAS_HEIGHT / 2);
      }
    });

    // 2. Weather Particles
    const weather = levelRef.current.weather;
    if (weather !== 'SUNNY') {
       // Spawn new particles
       if (particlesRef.current.length < 150) {
          const spawnX = Math.random() * CANVAS_WIDTH;
          particlesRef.current.push({
             x: spawnX,
             y: -10,
             speedX: weather === 'RAIN' ? -1 : Math.sin(Date.now() / 1000), 
             speedY: weather === 'RAIN' ? 8 + Math.random() * 4 : 1 + Math.random(), // Rain fast, Snow slow
             size: weather === 'RAIN' ? 2 : 3 + Math.random() * 2,
             life: 1
          });
       }
    }

    // Update Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
      const p = particlesRef.current[i];
      p.x += p.speedX;
      p.y += p.speedY;

      // Remove off screen
      if (p.y > CANVAS_HEIGHT) {
         particlesRef.current.splice(i, 1);
      }
    }
  };

  const update = () => {
    updateEnvironment();

    if (gameState.status !== GameStatus.PLAYING) return;

    const player = playerRef.current;
    const entities = entitiesRef.current;

    // --- Player Movement ---
    if (keysRef.current['ArrowLeft']) {
      player.vel.x = -MOVE_SPEED;
      player.facingRight = false;
    } else if (keysRef.current['ArrowRight']) {
      player.vel.x = MOVE_SPEED;
      player.facingRight = true;
    } else {
      player.vel.x = 0;
    }

    if ((keysRef.current['Space'] || keysRef.current['ArrowUp']) && player.isGrounded) {
      player.vel.y = JUMP_FORCE;
      player.isGrounded = false;
    }

    // --- Physics ---
    player.vel.y += GRAVITY;
    if (player.vel.y > TERMINAL_VELOCITY) player.vel.y = TERMINAL_VELOCITY;

    // Apply X
    player.pos.x += player.vel.x;

    // X Collisions
    player.isGrounded = false;

    if (player.pos.x < 0) player.pos.x = 0;
    if (player.pos.x > levelRef.current.width - player.size.x) player.pos.x = levelRef.current.width - player.size.x;

    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.x > 0) {
            player.pos.x = ent.pos.x - player.size.x;
          } else if (player.vel.x < 0) {
            player.pos.x = ent.pos.x + ent.size.x;
          }
        }
      }
    }

    // Apply Y
    player.pos.y += player.vel.y;

    // Y Collisions
    let landed = false;
    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.y > 0) { // Falling down
            player.pos.y = ent.pos.y - player.size.y;
            player.vel.y = 0;
            landed = true;
          } else if (player.vel.y < 0) { // Jumping up
            player.pos.y = ent.pos.y + ent.size.y;
            player.vel.y = 0;
          }
        }
      }
    }
    player.isGrounded = landed;

    if (player.pos.y > levelRef.current.height + 100) {
      onGameOver();
      return;
    }

    // --- Interactables ---
    if (player.isInvulnerable) {
      player.invulnerableTimer--;
      if (player.invulnerableTimer <= 0) player.isInvulnerable = false;
    }

    entities.forEach(ent => {
      if (ent.isDead) return;

      if (ent.type === EntityType.ENEMY) {
        ent.pos.x += ent.vel.x;
        if (ent.patrolEnd && ent.pos.x >= ent.patrolEnd) ent.vel.x = -Math.abs(ent.vel.x);
        if (ent.patrolStart && ent.pos.x <= ent.patrolStart) ent.vel.x = Math.abs(ent.vel.x);
      }

      if (checkCollision(player, ent)) {
        if (ent.type === EntityType.COIN) {
          ent.isDead = true;
          setGameState(prev => ({ ...prev, score: prev.score + 100, coinsCollected: prev.coinsCollected + 1 }));
        } else if (ent.type === EntityType.FLAG) {
          // Gate collision - trigger win
          onLevelComplete();
        } else if (ent.type === EntityType.SPIKE) {
           if (!player.isInvulnerable) handleDamage(player);
        } else if (ent.type === EntityType.ENEMY) {
          const hitFromTop = player.vel.y > 0 && (player.pos.y + player.size.y) < (ent.pos.y + ent.size.y * 0.7);
          if (hitFromTop) {
            ent.isDead = true;
            player.vel.y = JUMP_FORCE / 2;
            setGameState(prev => ({ ...prev, score: prev.score + 200 }));
          } else {
             if (!player.isInvulnerable) handleDamage(player);
          }
        }
      }
    });

    // --- Camera Follow ---
    const targetCamX = player.pos.x - CANVAS_WIDTH / 3;
    cameraRef.current.x += (targetCamX - cameraRef.current.x) * 0.1;
    if (cameraRef.current.x < 0) cameraRef.current.x = 0;
    const maxCamX = levelRef.current.width - CANVAS_WIDTH;
    if (cameraRef.current.x > maxCamX) cameraRef.current.x = maxCamX;
  };

  const handleDamage = (player: Player) => {
    player.isInvulnerable = true;
    player.invulnerableTimer = 120;
    player.vel.y = -6;
    player.vel.x = player.facingRight ? -4 : 4;
    onPlayerHit();
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const cameraX = Math.floor(cameraRef.current.x);
    const player = playerRef.current;
    const weather = levelRef.current.weather;

    // 1. Background
    ctx.fillStyle = levelRef.current.backgroundColor;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // 2. Draw Moving Clouds (Parallax)
    ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
    cloudsRef.current.forEach(cloud => {
        // Simple parallax: Cloud moves left naturally, plus moves slower relative to camera
        const parallaxX = cloud.x - (cameraX * 0.2); 
        // Wrap for rendering
        const renderX = ((parallaxX % (CANVAS_WIDTH * 2)) + (CANVAS_WIDTH * 2)) % (CANVAS_WIDTH * 2) - 200;

        ctx.beginPath();
        ctx.arc(renderX, cloud.y, cloud.size, 0, Math.PI * 2);
        ctx.arc(renderX + cloud.size * 0.8, cloud.y + cloud.size * 0.2, cloud.size * 0.9, 0, Math.PI * 2);
        ctx.arc(renderX - cloud.size * 0.8, cloud.y + cloud.size * 0.1, cloud.size * 0.7, 0, Math.PI * 2);
        ctx.fill();
    });

    ctx.save();
    ctx.translate(-cameraX, 0);

    // 3. Draw Level Entities
    entitiesRef.current.forEach(ent => {
      if (ent.isDead) return;

      if (ent.type === EntityType.PLATFORM) {
        ctx.fillStyle = COLORS.ground;
        ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
        if (ent.size.y > 10) {
           ctx.fillStyle = COLORS.dirt;
           ctx.fillRect(ent.pos.x, ent.pos.y + 10, ent.size.x, ent.size.y - 10);
        }
        ctx.strokeStyle = '#14532D';
        ctx.lineWidth = 2;
        ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      } 
      else if (ent.type === EntityType.COIN) {
        ctx.fillStyle = COLORS.coin;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2, ent.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = COLORS.coinShine;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2 - 3, ent.pos.y + ent.size.y/2 - 3, 3, 0, Math.PI * 2);
        ctx.fill();
        ent.pos.y += Math.sin(Date.now() / 200) * 0.2;
      }
      else if (ent.type === EntityType.SPIKE) {
        ctx.fillStyle = COLORS.spike;
        ctx.beginPath();
        const numSpikes = Math.floor(ent.size.x / 10);
        for(let i=0; i<numSpikes; i++) {
            ctx.moveTo(ent.pos.x + i * 10, ent.pos.y + ent.size.y);
            ctx.lineTo(ent.pos.x + i * 10 + 5, ent.pos.y);
            ctx.lineTo(ent.pos.x + i * 10 + 10, ent.pos.y + ent.size.y);
        }
        ctx.fill();
      }
      else if (ent.type === EntityType.ENEMY) {
         ctx.fillStyle = COLORS.enemy;
         ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         ctx.fillStyle = '#fff';
         ctx.fillRect(ent.pos.x + (ent.vel.x > 0 ? 18 : 4), ent.pos.y + 5, 8, 8);
         ctx.fillStyle = '#000';
         ctx.fillRect(ent.pos.x + (ent.vel.x > 0 ? 20 : 6), ent.pos.y + 7, 4, 4);
         ctx.strokeStyle = '#000';
         ctx.lineWidth = 2;
         ctx.beginPath();
         if (ent.vel.x > 0) {
            ctx.moveTo(ent.pos.x + 18, ent.pos.y + 4);
            ctx.lineTo(ent.pos.x + 26, ent.pos.y + 8);
         } else {
            ctx.moveTo(ent.pos.x + 12, ent.pos.y + 8);
            ctx.lineTo(ent.pos.x + 4, ent.pos.y + 4);
         }
         ctx.stroke();
      }
      else if (ent.type === EntityType.FLAG) {
         // Draw Big Gate / Castle Door
         // Main Frame
         ctx.fillStyle = COLORS.gateLight || '#9CA3AF';
         ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);

         // Dark Doorway
         ctx.fillStyle = COLORS.gateDark || '#374151';
         ctx.beginPath();
         ctx.roundRect(ent.pos.x + 15, ent.pos.y + 20, ent.size.x - 30, ent.size.y - 20, 10);
         ctx.fill();

         // Details (Stones)
         ctx.strokeStyle = '#4B5563';
         ctx.lineWidth = 2;
         ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);

         // Arch stones
         ctx.beginPath();
         ctx.moveTo(ent.pos.x, ent.pos.y + 20);
         ctx.lineTo(ent.pos.x + ent.size.x, ent.pos.y + 20);
         ctx.stroke();
      }
    });

    // 4. Draw Player
    if (player.isInvulnerable && Math.floor(Date.now() / 100) % 2 === 0) {
       ctx.globalAlpha = 0.5;
    }

    ctx.fillStyle = COLORS.bear;
    ctx.beginPath();
    ctx.roundRect(player.pos.x, player.pos.y, player.size.x, player.size.y, 5);
    ctx.fill();

    ctx.beginPath();
    ctx.arc(player.pos.x + 5, player.pos.y + 2, 6, 0, Math.PI*2);
    ctx.arc(player.pos.x + player.size.x - 5, player.pos.y + 2, 6, 0, Math.PI*2);
    ctx.fill();

    ctx.fillStyle = COLORS.bearFace;
    const faceX = player.facingRight ? player.pos.x + 12 : player.pos.x + 2;
    ctx.beginPath();
    ctx.roundRect(faceX, player.pos.y + 8, 16, 12, 4);
    ctx.fill();

    ctx.fillStyle = '#000';
    const eyeOffsetX = player.facingRight ? 4 : 0;
    ctx.beginPath();
    ctx.arc(faceX + 4 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.arc(faceX + 10 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.fill();

    ctx.beginPath();
    ctx.ellipse(faceX + 7 + eyeOffsetX, player.pos.y + 16, 3, 2, 0, 0, Math.PI*2);
    ctx.fill();

    ctx.globalAlpha = 1.0;
    ctx.restore();

    // 5. Draw Weather (Screen Space - On top of everything)
    if (weather === 'RAIN') {
        ctx.strokeStyle = 'rgba(173, 216, 230, 0.6)';
        ctx.lineWidth = 2;
        particlesRef.current.forEach(p => {
            ctx.beginPath();
            ctx.moveTo(p.x, p.y);
            ctx.lineTo(p.x - 2, p.y + 10);
            ctx.stroke();
        });
    } else if (weather === 'SNOW') {
        ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
        particlesRef.current.forEach(p => {
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fill();
        });
    }
  };

  const loop = () => {
    update();
    draw();
    requestRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(loop);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [gameState.status]);

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      className="block bg-black rounded-lg shadow-2xl border-4 border-gray-700 mx-auto"
      style={{ maxWidth: '100%', maxHeight: '80vh', imageRendering: 'pixelated' }}
    />
  );
};

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  VICTORY = 'VICTORY',
  REVIVE_PROMPT = 'REVIVE_PROMPT'
}

export enum EntityType {
  PLAYER = 'PLAYER',
  PLATFORM = 'PLATFORM',
  COIN = 'COIN',
  ENEMY = 'ENEMY',
  SPIKE = 'SPIKE',
  FLAG = 'FLAG', // Now represents the Gate/Door
  LAVA = 'LAVA',
  PROJECTILE = 'PROJECTILE'
}

export type WeatherType = 'SUNNY' | 'RAIN' | 'SNOW';
export type EnemyVariant = 'NORMAL' | 'TANK' | 'FAST';

export interface Vector {
  x: number;
  y: number;
}

export interface Entity {
  id: string;
  type: EntityType;
  pos: Vector;
  size: Vector;
  vel: Vector;
  color?: string;
  isDead?: boolean;

  // Enemy specific
  patrolStart?: number; 
  patrolEnd?: number;   
  enemyVariant?: EnemyVariant;
  health?: number;
  maxHealth?: number;
}

export interface Player extends Entity {
  isGrounded: boolean;
  facingRight: boolean;
  isInvulnerable: boolean;
  invulnerableTimer: number;
  shootCooldown: number;
}

export interface LevelData {
  id: number;
  name: string;
  width: number;
  height: number;
  entities: Entity[];
  spawnPoint: Vector;
  backgroundColor: string;
  weather: WeatherType;
}

export interface GameState {
  status: GameStatus;
  currentLevelId: number;
  score: number;
  lives: number;
  coinsCollected: number;
}

