class AudioController {
  ctx: AudioContext | null = null;
  bgmNodes: { osc: OscillatorNode, gain: GainNode }[] = [];
  isMuted: boolean = false;
  isPlayingBGM: boolean = false;
  bgmInterval: number | null = null;

  init() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.ctx.state === 'suspended') {
      this.ctx.resume();
    }
  }

  // Helper to create a beep
  private playTone(freq: number, type: OscillatorType, duration: number, vol: number = 0.1, slideTo: number | null = null) {
    if (!this.ctx || this.isMuted) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, this.ctx.currentTime);
    if (slideTo) {
      osc.frequency.linearRampToValueAtTime(slideTo, this.ctx.currentTime + duration);
    }

    gain.gain.setValueAtTime(vol, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration);

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    osc.start();
    osc.stop(this.ctx.currentTime + duration);
  }

  playJump() {
    this.playTone(150, 'square', 0.1, 0.1, 300);
  }

  playShoot() {
    // Noise-like effect or high pitch sweep down
    this.playTone(800, 'sawtooth', 0.1, 0.05, 100);
  }

  playCoin() {
    if (!this.ctx || this.isMuted) return;
    const now = this.ctx.currentTime;
    // Two notes: B5, E6
    this.playTone(987, 'sine', 0.1, 0.1); // B5
    setTimeout(() => this.playTone(1318, 'sine', 0.2, 0.1), 100); // E6
  }

  playKill() {
    // Low thud
    this.playTone(100, 'square', 0.1, 0.1, 50);
  }

  playDamage() {
    // Dissonant slide
    this.playTone(200, 'sawtooth', 0.3, 0.1, 50);
  }

  playPowerUp() {
    // Happy rising slide (Drinking wine)
    this.playTone(300, 'sine', 0.4, 0.2, 800);
    setTimeout(() => this.playTone(400, 'square', 0.4, 0.1, 900), 100);
  }

  playRoar() {
    // Scary low growl
    this.playTone(150, 'sawtooth', 0.4, 0.15, 50);
  }

  playWin() {
    if (!this.ctx || this.isMuted) return;
    // Simple Arpeggio
    [523, 659, 783, 1046].forEach((freq, i) => {
        setTimeout(() => this.playTone(freq, 'square', 0.2, 0.1), i * 150);
    });
  }

  startBGM(type: 'NORMAL' | 'CAVE' = 'NORMAL') {
    // If already playing, check if we need to switch? 
    // For simplicity, stop previous if any (handled by GameCanvas useEffect cleanup), then start new.
    this.stopBGM();

    if (!this.ctx || this.isMuted) return;
    this.isPlayingBGM = true;

    let beat = 0;
    let sequence: number[] = [];
    let speed = 250;

    if (type === 'CAVE') {
        // Cave music: Slower, deeper, echoing feeling (simulated by sequence)
        // D minor arpeggio-ish: D, F, A, D
        sequence = [73, 0, 87, 0, 110, 0, 146, 0, 110, 0, 87, 0]; 
        speed = 400; // Slower
    } else {
        // Normal upbeat
        sequence = [110, 0, 110, 0, 130, 0, 146, 130];
        speed = 250;
    }

    this.bgmInterval = window.setInterval(() => {
        if (!this.ctx || this.isMuted) return;
        const freq = sequence[beat % sequence.length];
        if (freq > 0) {
            const osc = this.ctx.createOscillator();
            const gain = this.ctx.createGain();

            // Cave uses sine for "hollow" sound, Normal uses triangle for "bouncy" sound
            osc.type = type === 'CAVE' ? 'sine' : 'triangle';

            osc.frequency.setValueAtTime(freq, this.ctx.currentTime);
            gain.gain.setValueAtTime(0.05, this.ctx.currentTime);

            // Cave has longer release for "echo"
            const release = type === 'CAVE' ? 0.8 : 0.2;
            gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + release);

            osc.connect(gain);
            gain.connect(this.ctx.destination);
            osc.start();
            osc.stop(this.ctx.currentTime + release);
        }
        beat++;
    }, speed);
  }

  stopBGM() {
    this.isPlayingBGM = false;
    if (this.bgmInterval) {
        clearInterval(this.bgmInterval);
        this.bgmInterval = null;
    }
  }
}

export const audio = new AudioController();

import { LevelData, EntityType, EnemyVariant } from './types';
import { CANVAS_HEIGHT, COLORS, TILE_SIZE } from './constants';

const createPlatform = (x: number, y: number, w: number, h: number, id: string) => ({
  id, type: EntityType.PLATFORM, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: h * TILE_SIZE }, vel: { x: 0, y: 0 }
});

const createCoin = (x: number, y: number, id: string) => ({
  id, type: EntityType.COIN, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 10 }, size: { x: 20, y: 20 }, vel: { x: 0, y: 0 }
});

const createWine = (x: number, y: number, id: string) => ({
  id, type: EntityType.WINE, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 5 }, size: { x: 20, y: 30 }, vel: { x: 0, y: 0 }
});

const createSpike = (x: number, y: number, w: number, id: string) => ({
  id, type: EntityType.SPIKE, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: TILE_SIZE / 2 }, vel: { x: 0, y: 0 }
});

const createGate = (x: number, y: number, id: string) => ({
  id, type: EntityType.FLAG, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - 80 }, size: { x: 80, y: 120 }, vel: { x: 0, y: 0 }
});

const createTrophy = (x: number, y: number, id: string) => ({
  id, type: EntityType.TROPHY, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - 40 }, size: { x: 40, y: 40 }, vel: { x: 0, y: 0 }
});

const createSpawner = (x: number, y: number, variant: EnemyVariant, cooldownFrames: number, id: string) => ({
  id,
  type: EntityType.SPAWNER,
  pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE },
  size: { x: TILE_SIZE, y: TILE_SIZE },
  vel: { x: 0, y: 0 },
  spawnVariant: variant,
  spawnCooldown: cooldownFrames,
  timeUntilSpawn: 0
});

// Enemy Factory
const createEnemy = (x: number, y: number, range: number, variant: EnemyVariant, id: string) => {
  let width = 30;
  let height = 30;
  let speed = 2;
  let health = 1;
  let color = COLORS.enemy;

  if (variant === 'TANK') {
    width = 50;
    height = 50;
    speed = 1;
    health = 3;
    color = COLORS.enemyTank;
  } else if (variant === 'FAST') {
    width = 25;
    height = 25;
    speed = 4;
    health = 1;
    color = COLORS.enemyFast;
  } else if (variant === 'BAT') {
    width = 30;
    height = 20;
    speed = 3;
    health = 1;
    color = COLORS.enemyBat;
  } else if (variant === 'SLIME') {
    width = 30;
    height = 20;
    speed = 1;
    health = 2;
    color = COLORS.enemySlime;
  }

  return {
    id, 
    type: EntityType.ENEMY, 
    pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - height }, 
    size: { x: width, y: height }, 
    vel: { x: speed, y: 0 }, 
    patrolStart: x * TILE_SIZE, 
    patrolEnd: (x + range) * TILE_SIZE,
    enemyVariant: variant,
    health,
    maxHealth: health,
    color
  };
};

