import React, { useEffect, useRef } from 'react';
import { CANVAS_WIDTH, CANVAS_HEIGHT, GRAVITY, TILE_SIZE, COLORS, PLAYER_WIDTH, PLAYER_HEIGHT, MOVE_SPEED, JUMP_FORCE, TERMINAL_VELOCITY, PROJECTILE_SPEED, PROJECTILE_SIZE, SHOOT_COOLDOWN, WINE_DURATION, WINE_SPEED_MULTIPLIER, WINE_JUMP_MULTIPLIER } from '../constants';
import { Entity, Player, EntityType, GameStatus, GameState, EnemyVariant } from '../types';
import { levels } from '../levels';
import { audio } from '../audio';

interface GameCanvasProps {
  levelId: number;
  gameState: GameState;
  setGameState: React.Dispatch<React.SetStateAction<GameState>>;
  onLevelComplete: () => void;
  onPlayerHit: () => void;
  onGameOver: () => void;
}

interface Cloud {
  x: number;
  y: number;
  speed: number;
  size: number;
}

interface Particle {
  x: number;
  y: number;
  speedX: number;
  speedY: number;
  size: number;
  life: number;
  color?: string; 
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ levelId, gameState, setGameState, onLevelComplete, onPlayerHit, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  // Game State Refs
  const levelRef = useRef(levels.find(l => l.id === levelId) || levels[0]);

  const playerRef = useRef<Player>({
    id: 'hero',
    type: EntityType.PLAYER,
    pos: { ...levelRef.current.spawnPoint },
    size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
    vel: { x: 0, y: 0 },
    isGrounded: false,
    facingRight: true,
    isInvulnerable: false,
    invulnerableTimer: 0,
    shootCooldown: 0,
    drunkTimer: 0
  });

  const entitiesRef = useRef<Entity[]>(JSON.parse(JSON.stringify(levelRef.current.entities)));
  const bulletsRef = useRef<Entity[]>([]); // Track active bullets
  const cameraRef = useRef({ x: 0 });
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Environment Refs
  const cloudsRef = useRef<Cloud[]>([]);
  const particlesRef = useRef<Particle[]>([]);

  // Init Clouds
  useEffect(() => {
    cloudsRef.current = Array.from({ length: 8 }).map(() => ({
      x: Math.random() * CANVAS_WIDTH * 2,
      y: Math.random() * (CANVAS_HEIGHT / 2),
      speed: 0.2 + Math.random() * 0.5,
      size: 30 + Math.random() * 40
    }));
  }, []);

  // Reset level when ID changes
  useEffect(() => {
    const newLevel = levels.find(l => l.id === levelId) || levels[0];
    levelRef.current = newLevel;
    entitiesRef.current = JSON.parse(JSON.stringify(newLevel.entities));
    bulletsRef.current = [];
    playerRef.current = {
      id: 'hero',
      type: EntityType.PLAYER,
      pos: { ...newLevel.spawnPoint },
      size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
      vel: { x: 0, y: 0 },
      isGrounded: false,
      facingRight: true,
      isInvulnerable: false,
      invulnerableTimer: 0,
      shootCooldown: 0,
      drunkTimer: 0
    };
    cameraRef.current.x = 0;
    particlesRef.current = []; 

    // Start BGM based on level weather/type
    audio.startBGM(newLevel.weather === 'CAVE' ? 'CAVE' : 'NORMAL');

    return () => {
      audio.stopBGM();
    }
  }, [levelId]);

  // Handle "Rescue"
  useEffect(() => {
    if (gameState.status === GameStatus.PLAYING) {
       if (playerRef.current.pos.y > levelRef.current.height + 50) {
           playerRef.current.pos = { ...levelRef.current.spawnPoint };
           playerRef.current.vel = { x: 0, y: 0 };
           cameraRef.current.x = Math.max(0, playerRef.current.pos.x - CANVAS_WIDTH / 3);
       }
       keysRef.current = {}; 
       audio.startBGM(levelRef.current.weather === 'CAVE' ? 'CAVE' : 'NORMAL');
    } else {
       audio.stopBGM();
    }
  }, [gameState.status]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.code] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.code] = false; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const checkCollision = (rect1: Entity, rect2: Entity) => {
    return (
      rect1.pos.x < rect2.pos.x + rect2.size.x &&
      rect1.pos.x + rect1.size.x > rect2.pos.x &&
      rect1.pos.y < rect2.pos.y + rect2.size.y &&
      rect1.pos.y + rect1.size.y > rect2.pos.y
    );
  };

  const spawnEnemy = (spawner: Entity) => {
      const variant = spawner.spawnVariant || 'NORMAL';
      let width = 30;
      let height = 30;
      let speed = 2;
      let health = 1;
      let color = COLORS.enemy;

      if (variant === 'TANK') {
        width = 50;
        height = 50;
        speed = 1;
        health = 3;
        color = COLORS.enemyTank;
      } else if (variant === 'FAST') {
        width = 25;
        height = 25;
        speed = 4;
        health = 1;
        color = COLORS.enemyFast;
      } else if (variant === 'BAT') {
        width = 30;
        height = 20;
        speed = 3;
        health = 1;
        color = COLORS.enemyBat;
      } else if (variant === 'SLIME') {
        width = 30;
        height = 20;
        speed = 1;
        health = 2;
        color = COLORS.enemySlime;
      }

      const dir = Math.random() > 0.5 ? 1 : -1;

      let spawnY = spawner.pos.y - height + spawner.size.y; 
      // Bats spawn higher
      if (variant === 'BAT') {
          spawnY -= 100; // Fly above
      }

      entitiesRef.current.push({
        id: `spawned_${Date.now()}_${Math.random()}`,
        type: EntityType.ENEMY,
        pos: { x: spawner.pos.x, y: spawnY }, 
        size: { x: width, y: height },
        vel: { x: speed * dir, y: 0 },
        patrolStart: spawner.pos.x - 400,
        patrolEnd: spawner.pos.x + 400,
        enemyVariant: variant,
        health,
        maxHealth: health,
        color
      });

      const dist = Math.abs(spawner.pos.x - playerRef.current.pos.x);
      if (dist < 800) {
          audio.playRoar();
      }
  };

  const updateEnvironment = () => {
    const player = playerRef.current;

    // 1. Clouds
    cloudsRef.current.forEach(cloud => {
      cloud.x -= cloud.speed;
      if (cloud.x + cloud.size * 2 < 0) {
         cloud.x = CANVAS_WIDTH * 2 + Math.random() * 200;
         cloud.y = Math.random() * (CANVAS_HEIGHT / 2);
      }
    });

    // 2. Weather Particles
    const weather = levelRef.current.weather;
    // Cave drip / dust
    if (weather === 'CAVE') {
        if (particlesRef.current.length < 50) {
            const spawnX = Math.random() * CANVAS_WIDTH;
            particlesRef.current.push({
                x: spawnX,
                y: -10,
                speedX: 0,
                speedY: 4 + Math.random() * 2, // Drips
                size: 2,
                life: 1,
                color: '#525252' // Grey drip
            });
        }
    } else if (weather !== 'SUNNY') {
       if (particlesRef.current.length < 150) {
          const spawnX = Math.random() * CANVAS_WIDTH;
          particlesRef.current.push({
             x: spawnX,
             y: -10,
             speedX: weather === 'RAIN' ? -1 : Math.sin(Date.now() / 1000), 
             speedY: weather === 'RAIN' ? 8 + Math.random() * 4 : 1 + Math.random(), 
             size: weather === 'RAIN' ? 2 : 3 + Math.random() * 2,
             life: 1
          });
       }
    }

    // 3. Drunk Particles
    if (player.drunkTimer > 0) {
       for (let k = 0; k < 2; k++) {
           particlesRef.current.push({
               x: player.pos.x + Math.random() * player.size.x,
               y: player.pos.y + player.size.y,
               speedX: (Math.random() - 0.5) * 2,
               speedY: -1 - Math.random() * 3, 
               size: Math.random() * 6 + 2,
               life: 0.8,
               color: Math.random() > 0.5 ? '#EF4444' : '#F59E0B'
           });
       }
    }

    // Update Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
      const p = particlesRef.current[i];
      p.x += p.speedX;
      p.y += p.speedY;

      if (p.color && p.color !== '#525252') { // Fire/Drunk
          p.life -= 0.05;
          p.size *= 0.95; 
      }

      if (p.y > CANVAS_HEIGHT || (p.color && p.life <= 0)) {
         particlesRef.current.splice(i, 1);
      }
    }
  };

  const update = () => {
    updateEnvironment();

    if (gameState.status !== GameStatus.PLAYING) return;

    const player = playerRef.current;
    const entities = entitiesRef.current;
    const bullets = bulletsRef.current;

    // --- Player State ---
    if (player.drunkTimer > 0) {
        player.drunkTimer--;
    }

    // --- Player Action: Shooting ---
    if (player.shootCooldown > 0) player.shootCooldown--;

    if ((keysRef.current['KeyF'] || keysRef.current['KeyJ']) && player.shootCooldown <= 0) {
        player.shootCooldown = SHOOT_COOLDOWN;
        if (player.drunkTimer > 0) player.shootCooldown = SHOOT_COOLDOWN / 2;

        const bVelX = player.facingRight ? PROJECTILE_SPEED : -PROJECTILE_SPEED;
        const bPosX = player.facingRight 
            ? player.pos.x + player.size.x 
            : player.pos.x - PROJECTILE_SIZE;

        bullets.push({
            id: `b_${Date.now()}`,
            type: EntityType.PROJECTILE,
            pos: { x: bPosX, y: player.pos.y + player.size.y / 2 - 4 },
            size: { x: PROJECTILE_SIZE, y: PROJECTILE_SIZE },
            vel: { x: bVelX, y: 0 }
        });
        audio.playShoot();
    }

    // --- Update Bullets ---
    for (let i = bullets.length - 1; i >= 0; i--) {
        const b = bullets[i];
        b.pos.x += b.vel.x;

        const distFromCam = Math.abs(b.pos.x - cameraRef.current.x);
        if (distFromCam > CANVAS_WIDTH + 100) {
            bullets.splice(i, 1);
            continue;
        }

        let bulletHit = false;

        for (const ent of entities) {
            if (ent.type === EntityType.ENEMY && !ent.isDead) {
                if (checkCollision(b, ent)) {
                    bulletHit = true;
                    ent.health = (ent.health || 1) - 1;
                    if (ent.health <= 0) {
                        ent.isDead = true;
                        setGameState(prev => ({ ...prev, score: prev.score + (ent.enemyVariant === 'TANK' ? 500 : 200) }));
                        audio.playKill();
                    } else {
                        ent.pos.x += b.vel.x > 0 ? 5 : -5;
                        audio.playDamage();
                    }
                    break;
                }
            } else if (ent.type === EntityType.PLATFORM) {
                if (checkCollision(b, ent)) {
                    bulletHit = true;
                    break;
                }
            }
        }

        if (bulletHit) {
            bullets.splice(i, 1);
        }
    }


    // --- Player Movement ---
    const effectiveSpeed = player.drunkTimer > 0 ? MOVE_SPEED * WINE_SPEED_MULTIPLIER : MOVE_SPEED;
    const effectiveJump = player.drunkTimer > 0 ? JUMP_FORCE * WINE_JUMP_MULTIPLIER : JUMP_FORCE;

    if (keysRef.current['ArrowLeft']) {
      player.vel.x = -effectiveSpeed;
      player.facingRight = false;
    } else if (keysRef.current['ArrowRight']) {
      player.vel.x = effectiveSpeed;
      player.facingRight = true;
    } else {
      player.vel.x = 0;
    }

    if ((keysRef.current['Space'] || keysRef.current['ArrowUp']) && player.isGrounded) {
      player.vel.y = effectiveJump;
      player.isGrounded = false;
      audio.playJump();
    }

    // --- Physics ---
    player.vel.y += GRAVITY;
    if (player.vel.y > TERMINAL_VELOCITY) player.vel.y = TERMINAL_VELOCITY;

    player.pos.x += player.vel.x;
    player.isGrounded = false;

    if (player.pos.x < 0) player.pos.x = 0;
    if (player.pos.x > levelRef.current.width - player.size.x) player.pos.x = levelRef.current.width - player.size.x;

    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.x > 0) {
            player.pos.x = ent.pos.x - player.size.x;
          } else if (player.vel.x < 0) {
            player.pos.x = ent.pos.x + ent.size.x;
          }
        }
      }
    }

    player.pos.y += player.vel.y;

    let landed = false;
    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.y > 0) {
            player.pos.y = ent.pos.y - player.size.y;
            player.vel.y = 0;
            landed = true;
          } else if (player.vel.y < 0) {
            player.pos.y = ent.pos.y + ent.size.y;
            player.vel.y = 0;
          }
        }
      }
    }
    player.isGrounded = landed;

    if (player.pos.y > levelRef.current.height + 100) {
      onGameOver();
      return;
    }

    // --- Interactables & Spawners ---
    if (player.isInvulnerable) {
      player.invulnerableTimer--;
      if (player.invulnerableTimer <= 0) player.isInvulnerable = false;
    }

    entities.forEach(ent => {
      if (ent.isDead) return;

      if (ent.type === EntityType.ENEMY) {
        // Special logic for Bats (Flying)
        if (ent.enemyVariant === 'BAT') {
             // Bob up and down
             ent.pos.y += Math.sin(Date.now() / 200) * 1;
             ent.pos.x += ent.vel.x;
        } else {
             // Normal Ground Logic
             ent.pos.x += ent.vel.x;
        }

        if (ent.patrolEnd && ent.pos.x >= ent.patrolEnd) ent.vel.x = -Math.abs(ent.vel.x);
        if (ent.patrolStart && ent.pos.x <= ent.patrolStart) ent.vel.x = Math.abs(ent.vel.x);
      } 
      else if (ent.type === EntityType.SPAWNER) {
          if (ent.spawnCooldown) {
              ent.timeUntilSpawn = (ent.timeUntilSpawn || 0) + 1;
              if (ent.timeUntilSpawn >= ent.spawnCooldown) {
                  const dist = Math.abs(ent.pos.x - player.pos.x);
                  if (dist < 800 && dist > 100) {
                      spawnEnemy(ent);
                      ent.timeUntilSpawn = 0;
                  }
              }
          }
      }

      // Collisions
      if (checkCollision(player, ent)) {
        if (ent.type === EntityType.COIN) {
          ent.isDead = true;
          setGameState(prev => ({ ...prev, score: prev.score + 100, coinsCollected: prev.coinsCollected + 1 }));
          audio.playCoin();
        } else if (ent.type === EntityType.WINE) {
          ent.isDead = true;
          player.drunkTimer = WINE_DURATION;
          audio.playPowerUp();
          setGameState(prev => ({ ...prev, score: prev.score + 500 }));

          // Instant particle burst for immediate feedback
          for (let k = 0; k < 20; k++) {
             particlesRef.current.push({
                 x: player.pos.x + player.size.x / 2,
                 y: player.pos.y + player.size.y / 2,
                 speedX: (Math.random() - 0.5) * 15,
                 speedY: (Math.random() - 0.5) * 15,
                 size: Math.random() * 6 + 4,
                 life: 1.0,
                 color: Math.random() > 0.5 ? '#EF4444' : '#F59E0B'
             });
          }

        } else if (ent.type === EntityType.FLAG || ent.type === EntityType.TROPHY) {
          onLevelComplete();
          audio.playWin();
        } else if (ent.type === EntityType.SPIKE) {
           if (!player.isInvulnerable) handleDamage(player);
        } else if (ent.type === EntityType.ENEMY) {
          const hitFromTop = player.vel.y > 0 && (player.pos.y + player.size.y) < (ent.pos.y + ent.size.y * 0.7);
          if (hitFromTop) {
            ent.isDead = true;
            player.vel.y = JUMP_FORCE / 2;
            setGameState(prev => ({ ...prev, score: prev.score + 200 }));
            audio.playKill();
          } else {
             if (!player.isInvulnerable) handleDamage(player);
          }
        }
      }
    });

    // --- Camera Follow ---
    const targetCamX = player.pos.x - CANVAS_WIDTH / 3;
    cameraRef.current.x += (targetCamX - cameraRef.current.x) * 0.1;
    if (cameraRef.current.x < 0) cameraRef.current.x = 0;
    const maxCamX = levelRef.current.width - CANVAS_WIDTH;
    if (cameraRef.current.x > maxCamX) cameraRef.current.x = maxCamX;
  };

  const handleDamage = (player: Player) => {
    player.isInvulnerable = true;
    player.invulnerableTimer = 120;
    player.vel.y = -6;
    player.vel.x = player.facingRight ? -4 : 4;
    onPlayerHit();
    audio.playDamage();
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const cameraX = Math.floor(cameraRef.current.x);
    const player = playerRef.current;
    const weather = levelRef.current.weather;
    const bullets = bulletsRef.current;

    // 1. Background
    ctx.fillStyle = levelRef.current.backgroundColor;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // 2. Clouds
    if (weather !== 'CAVE') {
        ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
        cloudsRef.current.forEach(cloud => {
            const parallaxX = cloud.x - (cameraX * 0.2); 
            const renderX = ((parallaxX % (CANVAS_WIDTH * 2)) + (CANVAS_WIDTH * 2)) % (CANVAS_WIDTH * 2) - 200;
            ctx.beginPath();
            ctx.arc(renderX, cloud.y, cloud.size, 0, Math.PI * 2);
            ctx.arc(renderX + cloud.size * 0.8, cloud.y + cloud.size * 0.2, cloud.size * 0.9, 0, Math.PI * 2);
            ctx.arc(renderX - cloud.size * 0.8, cloud.y + cloud.size * 0.1, cloud.size * 0.7, 0, Math.PI * 2);
            ctx.fill();
        });
    }

    ctx.save();
    ctx.translate(-cameraX, 0);

    // 3. Draw Level Entities
    entitiesRef.current.forEach(ent => {
      if (ent.isDead) return;
      if (ent.type === EntityType.SPAWNER) return;

      if (ent.type === EntityType.PLATFORM) {
        ctx.fillStyle = levelRef.current.groundColor || COLORS.ground;
        ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);

        // Dirt detail (only if not cave, or custom cave dirt)
        if (ent.size.y > 10) {
           ctx.fillStyle = levelRef.current.groundColor ? '#171717' : COLORS.dirt;
           ctx.globalAlpha = 0.3;
           ctx.fillRect(ent.pos.x, ent.pos.y + 10, ent.size.x, ent.size.y - 10);
           ctx.globalAlpha = 1.0;
        }
        ctx.strokeStyle = '#000';
        ctx.lineWidth = 2;
        ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      } 
      else if (ent.type === EntityType.COIN) {
        ctx.fillStyle = COLORS.coin;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2, ent.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = COLORS.coinShine;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2 - 3, ent.pos.y + ent.size.y/2 - 3, 3, 0, Math.PI * 2);
        ctx.fill();
      }
      else if (ent.type === EntityType.WINE) {
        ctx.fillStyle = COLORS.wine;
        ctx.fillRect(ent.pos.x + 4, ent.pos.y + 10, 12, 20);
        ctx.fillRect(ent.pos.x + 7, ent.pos.y, 6, 10);
        ctx.fillStyle = COLORS.wineLabel;
        ctx.fillRect(ent.pos.x + 5, ent.pos.y + 15, 10, 8);
        ctx.strokeStyle = COLORS.wineLabel;
        ctx.strokeRect(ent.pos.x + 4, ent.pos.y + 10, 12, 20);
        ent.pos.y += Math.sin(Date.now() / 150) * 0.3;
      }
      else if (ent.type === EntityType.SPIKE) {
        ctx.fillStyle = levelRef.current.spikeColor || COLORS.spike;
        ctx.beginPath();
        const numSpikes = Math.floor(ent.size.x / 10);
        for(let i=0; i<numSpikes; i++) {
            ctx.moveTo(ent.pos.x + i * 10, ent.pos.y + ent.size.y);
            ctx.lineTo(ent.pos.x + i * 10 + 5, ent.pos.y);
            ctx.lineTo(ent.pos.x + i * 10 + 10, ent.pos.y + ent.size.y);
        }
        ctx.fill();
      }
      else if (ent.type === EntityType.TROPHY) {
        ctx.fillStyle = COLORS.trophy;
        // Cup part
        ctx.beginPath();
        ctx.moveTo(ent.pos.x + 5, ent.pos.y + 5);
        ctx.lineTo(ent.pos.x + 35, ent.pos.y + 5);
        ctx.bezierCurveTo(ent.pos.x + 35, ent.pos.y + 25, ent.pos.x + 5, ent.pos.y + 25, ent.pos.x + 5, ent.pos.y + 5);
        ctx.fill();
        // Base
        ctx.fillStyle = COLORS.trophyBase;
        ctx.fillRect(ent.pos.x + 15, ent.pos.y + 25, 10, 5);
        ctx.fillRect(ent.pos.x + 10, ent.pos.y + 30, 20, 5);
        // Shine
        ctx.fillStyle = '#FFF';
        ctx.globalAlpha = 0.5;
        ctx.beginPath();
        ctx.arc(ent.pos.x + 15, ent.pos.y + 10, 3, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1.0;
      }
      else if (ent.type === EntityType.FLAG) {
         ctx.fillStyle = COLORS.gateLight || '#9CA3AF';
         ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         ctx.fillStyle = COLORS.gateDark || '#374151';
         ctx.beginPath();
         ctx.roundRect(ent.pos.x + 15, ent.pos.y + 20, ent.size.x - 30, ent.size.y - 20, 10);
         ctx.fill();
         ctx.strokeStyle = '#4B5563';
         ctx.lineWidth = 2;
         ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      }
      else if (ent.type === EntityType.ENEMY) {
         ctx.fillStyle = ent.color || COLORS.enemy;

         if (ent.enemyVariant === 'BAT') {
             // Draw Bat Wings
             ctx.fillStyle = ent.color || COLORS.enemyBat;
             ctx.beginPath();
             ctx.arc(ent.pos.x + 15, ent.pos.y + 10, 10, 0, Math.PI * 2); // Body
             ctx.fill();
             // Wings
             const wingFlap = Math.sin(Date.now() / 50) * 10;
             ctx.beginPath();
             ctx.moveTo(ent.pos.x + 5, ent.pos.y + 10);
             ctx.lineTo(ent.pos.x - 10, ent.pos.y + 5 + wingFlap);
             ctx.lineTo(ent.pos.x + 5, ent.pos.y + 15);
             ctx.fill();
             ctx.beginPath();
             ctx.moveTo(ent.pos.x + 25, ent.pos.y + 10);
             ctx.lineTo(ent.pos.x + 40, ent.pos.y + 5 + wingFlap);
             ctx.lineTo(ent.pos.x + 25, ent.pos.y + 15);
             ctx.fill();
         } else if (ent.enemyVariant === 'SLIME') {
             // Slime shape
             ctx.beginPath();
             ctx.arc(ent.pos.x + 15, ent.pos.y + 15, 15, Math.PI, 0); // Top
             ctx.lineTo(ent.pos.x + 30, ent.pos.y + 20);
             ctx.lineTo(ent.pos.x, ent.pos.y + 20);
             ctx.fill();
         } else {
             // Default Box
             ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         }

         // Eyes
         ctx.fillStyle = '#fff';
         const lookDir = ent.vel.x > 0 ? 1 : 0;
         if (ent.enemyVariant === 'BAT' || ent.enemyVariant === 'SLIME') {
             // Simple eyes
             ctx.fillRect(ent.pos.x + 10, ent.pos.y + 8, 4, 4);
             ctx.fillRect(ent.pos.x + 18, ent.pos.y + 8, 4, 4);
         } else {
             const eyeSize = ent.size.x * 0.2;
             ctx.fillRect(ent.pos.x + (lookDir ? ent.size.x * 0.6 : ent.size.x * 0.1), ent.pos.y + ent.size.y * 0.2, eyeSize, eyeSize);
             ctx.fillStyle = '#000';
             const pupilSize = eyeSize * 0.5;
             ctx.fillRect(ent.pos.x + (lookDir ? ent.size.x * 0.65 : ent.size.x * 0.15), ent.pos.y + ent.size.y * 0.25, pupilSize, pupilSize);
         }

         if (ent.enemyVariant === 'TANK' && ent.health && ent.maxHealth) {
             const hpPct = ent.health / ent.maxHealth;
             ctx.fillStyle = 'red';
             ctx.fillRect(ent.pos.x, ent.pos.y - 10, ent.size.x, 5);
             ctx.fillStyle = 'green';
             ctx.fillRect(ent.pos.x, ent.pos.y - 10, ent.size.x * hpPct, 5);
         }
      }
    });

    // 4. Draw Bullets
    ctx.fillStyle = COLORS.projectile;
    bullets.forEach(b => {
        ctx.beginPath();
        ctx.arc(b.pos.x + b.size.x/2, b.pos.y + b.size.y/2, b.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 5;
        ctx.shadowColor = 'white';
        ctx.fill();
        ctx.shadowBlur = 0;
    });

    // 5. Draw Player
    if (player.isInvulnerable && Math.floor(Date.now() / 100) % 2 === 0) {
       ctx.globalAlpha = 0.5;
    }

    ctx.fillStyle = COLORS.bear;
    ctx.beginPath();
    ctx.roundRect(player.pos.x, player.pos.y, player.size.x, player.size.y, 5);
    ctx.fill();

    ctx.beginPath();
    ctx.arc(player.pos.x + 5, player.pos.y + 2, 6, 0, Math.PI*2);
    ctx.arc(player.pos.x + player.size.x - 5, player.pos.y + 2, 6, 0, Math.PI*2);
    ctx.fill();

    // Drunk Face color change
    ctx.fillStyle = player.drunkTimer > 0 ? COLORS.bearFaceDrunk : COLORS.bearFace;
    const faceX = player.facingRight ? player.pos.x + 12 : player.pos.x + 2;
    ctx.beginPath();
    ctx.roundRect(faceX, player.pos.y + 8, 16, 12, 4);
    ctx.fill();

    ctx.fillStyle = '#000';
    const eyeOffsetX = player.facingRight ? 4 : 0;
    ctx.beginPath();
    ctx.arc(faceX + 4 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.arc(faceX + 10 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.fill();

    ctx.beginPath();
    ctx.ellipse(faceX + 7 + eyeOffsetX, player.pos.y + 16, 3, 2, 0, 0, Math.PI*2);
    ctx.fill();

    ctx.fillStyle = COLORS.gun;
    const gunX = player.facingRight ? player.pos.x + 20 : player.pos.x - 5;
    const gunY = player.pos.y + 15;
    ctx.fillRect(gunX, gunY, 15, 6); // Barrel
    ctx.fillRect(player.facingRight ? gunX : gunX + 10, gunY + 2, 5, 8); // Handle

    ctx.globalAlpha = 1.0;
    ctx.restore();

    // 6. Draw Weather and Particles
    if (weather === 'RAIN') {
        ctx.strokeStyle = 'rgba(173, 216, 230, 0.6)';
        ctx.lineWidth = 2;
        particlesRef.current.forEach(p => {
            if (!p.color) { // Rain
                ctx.beginPath();
                ctx.moveTo(p.x, p.y);
                ctx.lineTo(p.x - 2, p.y + 10);
                ctx.stroke();
            }
        });
    } else if (weather === 'SNOW') {
        ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
        particlesRef.current.forEach(p => {
             if (!p.color) { // Snow
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                ctx.fill();
             }
        });
    } else if (weather === 'CAVE') {
        // Cave Drips
        ctx.fillStyle = '#737373';
        particlesRef.current.forEach(p => {
             if (p.color === '#525252') { 
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                ctx.fill();
             }
        });
    }

    // Draw Fire/Effect Particles (On top)
    particlesRef.current.forEach(p => {
        if (p.color && p.color !== '#525252') {
            ctx.fillStyle = p.color;
            ctx.globalAlpha = p.life;
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fill();
            ctx.globalAlpha = 1.0;
        }
    });
  };

  const loop = () => {
    update();
    draw();
    requestRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(loop);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [gameState.status]);

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      className="block bg-black rounded-lg shadow-2xl border-4 border-gray-700 mx-auto"
      style={{ maxWidth: '100%', maxHeight: '80vh', imageRendering: 'pixelated' }}
    />
  );
};

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  VICTORY = 'VICTORY',
  REVIVE_PROMPT = 'REVIVE_PROMPT'
}

export enum EntityType {
  PLAYER = 'PLAYER',
  PLATFORM = 'PLATFORM',
  COIN = 'COIN',
  ENEMY = 'ENEMY',
  SPIKE = 'SPIKE',
  FLAG = 'FLAG', // Gate/Door
  TROPHY = 'TROPHY', // New win condition
  LAVA = 'LAVA',
  PROJECTILE = 'PROJECTILE',
  SPAWNER = 'SPAWNER',
  WINE = 'WINE'
}

export type WeatherType = 'SUNNY' | 'RAIN' | 'SNOW' | 'CAVE';
export type EnemyVariant = 'NORMAL' | 'TANK' | 'FAST' | 'BAT' | 'SLIME';

export interface Vector {
  x: number;
  y: number;
}

export interface Entity {
  id: string;
  type: EntityType;
  pos: Vector;
  size: Vector;
  vel: Vector;
  color?: string;
  isDead?: boolean;

  // Enemy specific
  patrolStart?: number; 
  patrolEnd?: number;   
  enemyVariant?: EnemyVariant;
  health?: number;
  maxHealth?: number;

  // Spawner specific
  spawnCooldown?: number;
  timeUntilSpawn?: number;
  spawnVariant?: EnemyVariant;
}

export interface Player extends Entity {
  isGrounded: boolean;
  facingRight: boolean;
  isInvulnerable: boolean;
  invulnerableTimer: number;
  shootCooldown: number;
  drunkTimer: number; // For the wine power-up
  // Physics optimization
  coyoteTimer: number; // Allows jumping shortly after leaving ground
  jumpBufferTimer: number; // Remembers jump press slightly before hitting ground
}

export interface LevelData {
  id: number;
  name: string;
  width: number;
  height: number;
  entities: Entity[];
  spawnPoint: Vector;
  backgroundColor: string;
  groundColor?: string; // Custom ground color
  spikeColor?: string;  // Custom spike color
  weather: WeatherType;
}

export interface GameState {
  status: GameStatus;
  currentLevelId: number;
  score: number;
  lives: number;
  coinsCollected: number;
}

export const CANVAS_WIDTH = 800;
export const CANVAS_HEIGHT = 450;
export const TILE_SIZE = 40;

// Physics & Feel
export const GRAVITY = 0.6;
export const TERMINAL_VELOCITY = 12;
export const MOVE_SPEED = 6; // Max speed
export const ACCELERATION = 0.8; // How fast we reach max speed
export const FRICTION = 0.82; // Ground friction
export const AIR_FRICTION = 0.95; // Air resistance (less friction)
export const JUMP_FORCE = -14;
export const COYOTE_TIME = 6; // Frames allowed to jump after falling off ledge
export const JUMP_BUFFER = 5; // Frames to buffer a jump input before landing

export const ENEMY_SPEED = 2;

// Weapon & Combat
export const PROJECTILE_SPEED = 12;
export const PROJECTILE_SIZE = 8;
export const SHOOT_COOLDOWN = 20; // Frames

// Wine Power-up
export const WINE_DURATION = 600; // 10 seconds (at 60fps)
export const WINE_SPEED_MULTIPLIER = 1.4; // Slightly reduced multiplier since base speed is dynamic now
export const WINE_JUMP_MULTIPLIER = 1.2;

export const PLAYER_WIDTH = 30;
export const PLAYER_HEIGHT = 30;

export const MAX_HEALTH = 3;
export const REVIVE_COST = 1;

export const COLORS = {
  sky: '#87CEEB',
  skyDark: '#1E3A8A', // Night level
  ground: '#4ADE80',
  groundDark: '#14532D',

  // Cave Colors
  caveBg: '#171717',
  caveGround: '#404040',
  caveGroundDark: '#262626',
  caveSpike: '#737373',

  dirt: '#854D0E',
  bear: '#92400E', // Brown
  bearFace: '#FCD34D',
  bearFaceDrunk: '#EF4444', // Red face when drunk
  gun: '#4B5563', // Grey gun
  projectile: '#FFF', // White bullet
  coin: '#FACC15',
  coinShine: '#FEF08A',
  wine: '#9333EA', // Purple bottle
  wineLabel: '#F3E8FF',
  trophy: '#FBBF24', // Gold Trophy
  trophyBase: '#78350F',

  // Enemy Variants
  enemy: '#DC2626',      // Red (Normal)
  enemyTank: '#7C3AED',  // Purple (Tank)
  enemyFast: '#EA580C',  // Orange (Fast)
  enemyBat: '#4C1D95',   // Deep Purple
  enemySlime: '#10B981', // Green

  spike: '#999999',
  lava: '#EF4444',
  lavaSurface: '#FCA5A5',
  flagPole: '#D1D5DB',
  flag: '#DC2626',
  gateDark: '#374151',
  gateLight: '#9CA3AF'
};

import React, { useEffect, useRef } from 'react';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, GRAVITY, TILE_SIZE, COLORS, PLAYER_WIDTH, PLAYER_HEIGHT, 
  MOVE_SPEED, JUMP_FORCE, TERMINAL_VELOCITY, PROJECTILE_SPEED, PROJECTILE_SIZE, SHOOT_COOLDOWN, 
  WINE_DURATION, WINE_SPEED_MULTIPLIER, WINE_JUMP_MULTIPLIER,
  ACCELERATION, FRICTION, AIR_FRICTION, COYOTE_TIME, JUMP_BUFFER
} from '../constants';
import { Entity, Player, EntityType, GameStatus, GameState, EnemyVariant } from '../types';
import { levels } from '../levels';
import { audio } from '../audio';

interface GameCanvasProps {
  levelId: number;
  gameState: GameState;
  setGameState: React.Dispatch<React.SetStateAction<GameState>>;
  onLevelComplete: () => void;
  onPlayerHit: () => void;
  onGameOver: () => void;
}

interface Cloud {
  x: number;
  y: number;
  speed: number;
  size: number;
}

interface Particle {
  x: number;
  y: number;
  speedX: number;
  speedY: number;
  size: number;
  life: number;
  color?: string; 
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ levelId, gameState, setGameState, onLevelComplete, onPlayerHit, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  // Game State Refs
  const levelRef = useRef(levels.find(l => l.id === levelId) || levels[0]);

  const playerRef = useRef<Player>({
    id: 'hero',
    type: EntityType.PLAYER,
    pos: { ...levelRef.current.spawnPoint },
    size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
    vel: { x: 0, y: 0 },
    isGrounded: false,
    facingRight: true,
    isInvulnerable: false,
    invulnerableTimer: 0,
    shootCooldown: 0,
    drunkTimer: 0,
    coyoteTimer: 0,
    jumpBufferTimer: 0
  });

  const entitiesRef = useRef<Entity[]>(JSON.parse(JSON.stringify(levelRef.current.entities)));
  const bulletsRef = useRef<Entity[]>([]); // Track active bullets
  const cameraRef = useRef({ x: 0 });
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Environment Refs
  const cloudsRef = useRef<Cloud[]>([]);
  const particlesRef = useRef<Particle[]>([]);

  // Init Clouds
  useEffect(() => {
    cloudsRef.current = Array.from({ length: 8 }).map(() => ({
      x: Math.random() * CANVAS_WIDTH * 2,
      y: Math.random() * (CANVAS_HEIGHT / 2),
      speed: 0.2 + Math.random() * 0.5,
      size: 30 + Math.random() * 40
    }));
  }, []);

  // Reset level when ID changes
  useEffect(() => {
    const newLevel = levels.find(l => l.id === levelId) || levels[0];
    levelRef.current = newLevel;
    entitiesRef.current = JSON.parse(JSON.stringify(newLevel.entities));
    bulletsRef.current = [];
    playerRef.current = {
      id: 'hero',
      type: EntityType.PLAYER,
      pos: { ...newLevel.spawnPoint },
      size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
      vel: { x: 0, y: 0 },
      isGrounded: false,
      facingRight: true,
      isInvulnerable: false,
      invulnerableTimer: 0,
      shootCooldown: 0,
      drunkTimer: 0,
      coyoteTimer: 0,
      jumpBufferTimer: 0
    };
    cameraRef.current.x = 0;
    particlesRef.current = []; 

    // Start BGM based on level weather/type
    audio.startBGM(newLevel.weather === 'CAVE' ? 'CAVE' : 'NORMAL');

    return () => {
      audio.stopBGM();
    }
  }, [levelId]);

  // Handle "Rescue"
  useEffect(() => {
    if (gameState.status === GameStatus.PLAYING) {
       if (playerRef.current.pos.y > levelRef.current.height + 50) {
           playerRef.current.pos = { ...levelRef.current.spawnPoint };
           playerRef.current.vel = { x: 0, y: 0 };
           cameraRef.current.x = Math.max(0, playerRef.current.pos.x - CANVAS_WIDTH / 3);
       }
       keysRef.current = {}; 
       audio.startBGM(levelRef.current.weather === 'CAVE' ? 'CAVE' : 'NORMAL');
    } else {
       audio.stopBGM();
    }
  }, [gameState.status]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { 
        keysRef.current[e.code] = true;
        // Jump Buffer: Record press even if in air
        if (e.code === 'Space' || e.code === 'ArrowUp') {
            playerRef.current.jumpBufferTimer = JUMP_BUFFER;
        }
    };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.code] = false; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const checkCollision = (rect1: Entity, rect2: Entity) => {
    return (
      rect1.pos.x < rect2.pos.x + rect2.size.x &&
      rect1.pos.x + rect1.size.x > rect2.pos.x &&
      rect1.pos.y < rect2.pos.y + rect2.size.y &&
      rect1.pos.y + rect1.size.y > rect2.pos.y
    );
  };

  const spawnEnemy = (spawner: Entity) => {
      const variant = spawner.spawnVariant || 'NORMAL';
      let width = 30;
      let height = 30;
      let speed = 2;
      let health = 1;
      let color = COLORS.enemy;

      if (variant === 'TANK') {
        width = 50;
        height = 50;
        speed = 1;
        health = 3;
        color = COLORS.enemyTank;
      } else if (variant === 'FAST') {
        width = 25;
        height = 25;
        speed = 4;
        health = 1;
        color = COLORS.enemyFast;
      } else if (variant === 'BAT') {
        width = 30;
        height = 20;
        speed = 3;
        health = 1;
        color = COLORS.enemyBat;
      } else if (variant === 'SLIME') {
        width = 30;
        height = 20;
        speed = 1;
        health = 2;
        color = COLORS.enemySlime;
      }

      const dir = Math.random() > 0.5 ? 1 : -1;

      let spawnY = spawner.pos.y - height + spawner.size.y; 
      // Bats spawn higher
      if (variant === 'BAT') {
          spawnY -= 100; // Fly above
      }

      entitiesRef.current.push({
        id: `spawned_${Date.now()}_${Math.random()}`,
        type: EntityType.ENEMY,
        pos: { x: spawner.pos.x, y: spawnY }, 
        size: { x: width, y: height },
        vel: { x: speed * dir, y: 0 },
        patrolStart: spawner.pos.x - 400,
        patrolEnd: spawner.pos.x + 400,
        enemyVariant: variant,
        health,
        maxHealth: health,
        color
      });

      const dist = Math.abs(spawner.pos.x - playerRef.current.pos.x);
      if (dist < 800) {
          audio.playRoar();
      }
  };

  const updateEnvironment = () => {
    const player = playerRef.current;

    // 1. Clouds
    cloudsRef.current.forEach(cloud => {
      cloud.x -= cloud.speed;
      if (cloud.x + cloud.size * 2 < 0) {
         cloud.x = CANVAS_WIDTH * 2 + Math.random() * 200;
         cloud.y = Math.random() * (CANVAS_HEIGHT / 2);
      }
    });

    // 2. Weather Particles
    const weather = levelRef.current.weather;
    // Cave drip / dust
    if (weather === 'CAVE') {
        if (particlesRef.current.length < 50) {
            const spawnX = Math.random() * CANVAS_WIDTH;
            particlesRef.current.push({
                x: spawnX,
                y: -10,
                speedX: 0,
                speedY: 4 + Math.random() * 2, // Drips
                size: 2,
                life: 1,
                color: '#525252' // Grey drip
            });
        }
    } else if (weather !== 'SUNNY') {
       if (particlesRef.current.length < 150) {
          const spawnX = Math.random() * CANVAS_WIDTH;
          particlesRef.current.push({
             x: spawnX,
             y: -10,
             speedX: weather === 'RAIN' ? -1 : Math.sin(Date.now() / 1000), 
             speedY: weather === 'RAIN' ? 8 + Math.random() * 4 : 1 + Math.random(), 
             size: weather === 'RAIN' ? 2 : 3 + Math.random() * 2,
             life: 1
          });
       }
    }

    // 3. Drunk Particles
    if (player.drunkTimer > 0) {
       for (let k = 0; k < 2; k++) {
           particlesRef.current.push({
               x: player.pos.x + Math.random() * player.size.x,
               y: player.pos.y + player.size.y,
               speedX: (Math.random() - 0.5) * 2,
               speedY: -1 - Math.random() * 3, 
               size: Math.random() * 6 + 2,
               life: 0.8,
               color: Math.random() > 0.5 ? '#EF4444' : '#F59E0B'
           });
       }
    }

    // Update Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
      const p = particlesRef.current[i];
      p.x += p.speedX;
      p.y += p.speedY;

      if (p.color && p.color !== '#525252') { // Fire/Drunk
          p.life -= 0.05;
          p.size *= 0.95; 
      }

      if (p.y > CANVAS_HEIGHT || (p.color && p.life <= 0)) {
         particlesRef.current.splice(i, 1);
      }
    }
  };

  const update = () => {
    updateEnvironment();

    if (gameState.status !== GameStatus.PLAYING) return;

    const player = playerRef.current;
    const entities = entitiesRef.current;
    const bullets = bulletsRef.current;

    // --- Player State ---
    if (player.drunkTimer > 0) {
        player.drunkTimer--;
    }
    if (player.jumpBufferTimer > 0) {
        player.jumpBufferTimer--;
    }

    // --- Player Action: Shooting ---
    if (player.shootCooldown > 0) player.shootCooldown--;

    if ((keysRef.current['KeyF'] || keysRef.current['KeyJ']) && player.shootCooldown <= 0) {
        player.shootCooldown = SHOOT_COOLDOWN;
        if (player.drunkTimer > 0) player.shootCooldown = SHOOT_COOLDOWN / 2;

        const bVelX = player.facingRight ? PROJECTILE_SPEED : -PROJECTILE_SPEED;
        const bPosX = player.facingRight 
            ? player.pos.x + player.size.x 
            : player.pos.x - PROJECTILE_SIZE;

        bullets.push({
            id: `b_${Date.now()}`,
            type: EntityType.PROJECTILE,
            pos: { x: bPosX, y: player.pos.y + player.size.y / 2 - 4 },
            size: { x: PROJECTILE_SIZE, y: PROJECTILE_SIZE },
            vel: { x: bVelX, y: 0 }
        });
        audio.playShoot();
    }

    // --- Update Bullets ---
    for (let i = bullets.length - 1; i >= 0; i--) {
        const b = bullets[i];
        b.pos.x += b.vel.x;

        const distFromCam = Math.abs(b.pos.x - cameraRef.current.x);
        if (distFromCam > CANVAS_WIDTH + 100) {
            bullets.splice(i, 1);
            continue;
        }

        let bulletHit = false;

        for (const ent of entities) {
            if (ent.type === EntityType.ENEMY && !ent.isDead) {
                if (checkCollision(b, ent)) {
                    bulletHit = true;
                    ent.health = (ent.health || 1) - 1;
                    if (ent.health <= 0) {
                        ent.isDead = true;
                        setGameState(prev => ({ ...prev, score: prev.score + (ent.enemyVariant === 'TANK' ? 500 : 200) }));
                        audio.playKill();
                    } else {
                        ent.pos.x += b.vel.x > 0 ? 5 : -5;
                        audio.playDamage();
                    }
                    break;
                }
            } else if (ent.type === EntityType.PLATFORM) {
                if (checkCollision(b, ent)) {
                    bulletHit = true;
                    break;
                }
            }
        }

        if (bulletHit) {
            bullets.splice(i, 1);
        }
    }


    // --- Player Movement (Improved Physics) ---
    const maxSpeed = player.drunkTimer > 0 ? MOVE_SPEED * WINE_SPEED_MULTIPLIER : MOVE_SPEED;
    const jumpForce = player.drunkTimer > 0 ? JUMP_FORCE * WINE_JUMP_MULTIPLIER : JUMP_FORCE;

    // Horizontal Movement with Acceleration
    if (keysRef.current['ArrowLeft']) {
      player.vel.x -= ACCELERATION;
      player.facingRight = false;
    } else if (keysRef.current['ArrowRight']) {
      player.vel.x += ACCELERATION;
      player.facingRight = true;
    } else {
      // Friction
      const friction = player.isGrounded ? FRICTION : AIR_FRICTION;
      player.vel.x *= friction;
      if (Math.abs(player.vel.x) < 0.1) player.vel.x = 0;
    }

    // Clamp speed
    if (player.vel.x > maxSpeed) player.vel.x = maxSpeed;
    if (player.vel.x < -maxSpeed) player.vel.x = -maxSpeed;

    // Coyote Time Logic
    if (player.isGrounded) {
        player.coyoteTimer = COYOTE_TIME;
    } else {
        if (player.coyoteTimer > 0) player.coyoteTimer--;
    }

    // Jump Logic (Buffer + Coyote)
    if (player.jumpBufferTimer > 0 && player.coyoteTimer > 0) {
        player.vel.y = jumpForce;
        player.isGrounded = false;
        player.coyoteTimer = 0; // Consume coyote time
        player.jumpBufferTimer = 0; // Consume buffer
        audio.playJump();
    }

    // Variable Jump Height (Release key to fall faster)
    if (player.vel.y < 0 && !keysRef.current['Space'] && !keysRef.current['ArrowUp']) {
        player.vel.y *= 0.5;
    }

    // --- Physics ---
    player.vel.y += GRAVITY;
    if (player.vel.y > TERMINAL_VELOCITY) player.vel.y = TERMINAL_VELOCITY;

    player.pos.x += player.vel.x;
    player.isGrounded = false;

    if (player.pos.x < 0) player.pos.x = 0;
    if (player.pos.x > levelRef.current.width - player.size.x) player.pos.x = levelRef.current.width - player.size.x;

    // X Collisions
    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.x > 0) {
            player.pos.x = ent.pos.x - player.size.x;
            player.vel.x = 0; // Stop momentum on wall hit
          } else if (player.vel.x < 0) {
            player.pos.x = ent.pos.x + ent.size.x;
            player.vel.x = 0;
          }
        }
      }
    }

    player.pos.y += player.vel.y;

    // Y Collisions
    let landed = false;
    for (const ent of entities) {
      if (ent.type === EntityType.PLATFORM) {
        if (checkCollision(player, ent)) {
          if (player.vel.y > 0) {
            player.pos.y = ent.pos.y - player.size.y;
            player.vel.y = 0;
            landed = true;
          } else if (player.vel.y < 0) {
            player.pos.y = ent.pos.y + ent.size.y;
            player.vel.y = 0;
          }
        }
      }
    }
    player.isGrounded = landed;

    if (player.pos.y > levelRef.current.height + 100) {
      onGameOver();
      return;
    }

    // --- Interactables & Spawners ---
    if (player.isInvulnerable) {
      player.invulnerableTimer--;
      if (player.invulnerableTimer <= 0) player.isInvulnerable = false;
    }

    entities.forEach(ent => {
      if (ent.isDead) return;

      if (ent.type === EntityType.ENEMY) {
        // Special logic for Bats (Flying)
        if (ent.enemyVariant === 'BAT') {
             // Bob up and down
             ent.pos.y += Math.sin(Date.now() / 200) * 1;
             ent.pos.x += ent.vel.x;
        } else {
             // Normal Ground Logic
             ent.pos.x += ent.vel.x;
        }

        if (ent.patrolEnd && ent.pos.x >= ent.patrolEnd) ent.vel.x = -Math.abs(ent.vel.x);
        if (ent.patrolStart && ent.pos.x <= ent.patrolStart) ent.vel.x = Math.abs(ent.vel.x);
      } 
      else if (ent.type === EntityType.SPAWNER) {
          if (ent.spawnCooldown) {
              ent.timeUntilSpawn = (ent.timeUntilSpawn || 0) + 1;
              if (ent.timeUntilSpawn >= ent.spawnCooldown) {
                  const dist = Math.abs(ent.pos.x - player.pos.x);
                  if (dist < 800 && dist > 100) {
                      spawnEnemy(ent);
                      ent.timeUntilSpawn = 0;
                  }
              }
          }
      }

      // Collisions
      if (checkCollision(player, ent)) {
        if (ent.type === EntityType.COIN) {
          ent.isDead = true;
          setGameState(prev => ({ ...prev, score: prev.score + 100, coinsCollected: prev.coinsCollected + 1 }));
          audio.playCoin();
        } else if (ent.type === EntityType.WINE) {
          ent.isDead = true;
          player.drunkTimer = WINE_DURATION;
          audio.playPowerUp();
          setGameState(prev => ({ ...prev, score: prev.score + 500 }));

          // Instant particle burst
          for (let k = 0; k < 20; k++) {
             particlesRef.current.push({
                 x: player.pos.x + player.size.x / 2,
                 y: player.pos.y + player.size.y / 2,
                 speedX: (Math.random() - 0.5) * 15,
                 speedY: (Math.random() - 0.5) * 15,
                 size: Math.random() * 6 + 4,
                 life: 1.0,
                 color: Math.random() > 0.5 ? '#EF4444' : '#F59E0B'
             });
          }

        } else if (ent.type === EntityType.FLAG || ent.type === EntityType.TROPHY) {
          onLevelComplete();
          audio.playWin();
        } else if (ent.type === EntityType.SPIKE) {
           if (!player.isInvulnerable) handleDamage(player);
        } else if (ent.type === EntityType.ENEMY) {
          const hitFromTop = player.vel.y > 0 && (player.pos.y + player.size.y) < (ent.pos.y + ent.size.y * 0.7);
          if (hitFromTop) {
            ent.isDead = true;
            player.vel.y = JUMP_FORCE / 2;
            setGameState(prev => ({ ...prev, score: prev.score + 200 }));
            audio.playKill();
          } else {
             if (!player.isInvulnerable) handleDamage(player);
          }
        }
      }
    });

    // --- Camera Follow ---
    const targetCamX = player.pos.x - CANVAS_WIDTH / 3;
    cameraRef.current.x += (targetCamX - cameraRef.current.x) * 0.1;
    if (cameraRef.current.x < 0) cameraRef.current.x = 0;
    const maxCamX = levelRef.current.width - CANVAS_WIDTH;
    if (cameraRef.current.x > maxCamX) cameraRef.current.x = maxCamX;
  };

  const handleDamage = (player: Player) => {
    player.isInvulnerable = true;
    player.invulnerableTimer = 120;
    player.vel.y = -6;
    player.vel.x = player.facingRight ? -4 : 4;
    onPlayerHit();
    audio.playDamage();
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const cameraX = Math.floor(cameraRef.current.x);
    const player = playerRef.current;
    const weather = levelRef.current.weather;
    const bullets = bulletsRef.current;

    // 1. Background
    ctx.fillStyle = levelRef.current.backgroundColor;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // 2. Clouds
    if (weather !== 'CAVE') {
        ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
        cloudsRef.current.forEach(cloud => {
            const parallaxX = cloud.x - (cameraX * 0.2); 
            const renderX = ((parallaxX % (CANVAS_WIDTH * 2)) + (CANVAS_WIDTH * 2)) % (CANVAS_WIDTH * 2) - 200;
            ctx.beginPath();
            ctx.arc(renderX, cloud.y, cloud.size, 0, Math.PI * 2);
            ctx.arc(renderX + cloud.size * 0.8, cloud.y + cloud.size * 0.2, cloud.size * 0.9, 0, Math.PI * 2);
            ctx.arc(renderX - cloud.size * 0.8, cloud.y + cloud.size * 0.1, cloud.size * 0.7, 0, Math.PI * 2);
            ctx.fill();
        });
    }

    ctx.save();
    ctx.translate(-cameraX, 0);

    // 3. Draw Level Entities
    entitiesRef.current.forEach(ent => {
      if (ent.isDead) return;
      if (ent.type === EntityType.SPAWNER) return;

      if (ent.type === EntityType.PLATFORM) {
        ctx.fillStyle = levelRef.current.groundColor || COLORS.ground;
        ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);

        // Dirt detail (only if not cave, or custom cave dirt)
        if (ent.size.y > 10) {
           ctx.fillStyle = levelRef.current.groundColor ? '#171717' : COLORS.dirt;
           ctx.globalAlpha = 0.3;
           ctx.fillRect(ent.pos.x, ent.pos.y + 10, ent.size.x, ent.size.y - 10);
           ctx.globalAlpha = 1.0;
        }
        ctx.strokeStyle = '#000';
        ctx.lineWidth = 2;
        ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      } 
      else if (ent.type === EntityType.COIN) {
        ctx.fillStyle = COLORS.coin;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2, ent.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = COLORS.coinShine;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2 - 3, ent.pos.y + ent.size.y/2 - 3, 3, 0, Math.PI * 2);
        ctx.fill();
      }
      else if (ent.type === EntityType.WINE) {
        ctx.fillStyle = COLORS.wine;
        ctx.fillRect(ent.pos.x + 4, ent.pos.y + 10, 12, 20);
        ctx.fillRect(ent.pos.x + 7, ent.pos.y, 6, 10);
        ctx.fillStyle = COLORS.wineLabel;
        ctx.fillRect(ent.pos.x + 5, ent.pos.y + 15, 10, 8);
        ctx.strokeStyle = COLORS.wineLabel;
        ctx.strokeRect(ent.pos.x + 4, ent.pos.y + 10, 12, 20);
        ent.pos.y += Math.sin(Date.now() / 150) * 0.3;
      }
      else if (ent.type === EntityType.SPIKE) {
        ctx.fillStyle = levelRef.current.spikeColor || COLORS.spike;
        ctx.beginPath();
        const numSpikes = Math.floor(ent.size.x / 10);
        for(let i=0; i<numSpikes; i++) {
            ctx.moveTo(ent.pos.x + i * 10, ent.pos.y + ent.size.y);
            ctx.lineTo(ent.pos.x + i * 10 + 5, ent.pos.y);
            ctx.lineTo(ent.pos.x + i * 10 + 10, ent.pos.y + ent.size.y);
        }
        ctx.fill();
      }
      else if (ent.type === EntityType.TROPHY) {
        ctx.fillStyle = COLORS.trophy;
        // Cup part
        ctx.beginPath();
        ctx.moveTo(ent.pos.x + 5, ent.pos.y + 5);
        ctx.lineTo(ent.pos.x + 35, ent.pos.y + 5);
        ctx.bezierCurveTo(ent.pos.x + 35, ent.pos.y + 25, ent.pos.x + 5, ent.pos.y + 25, ent.pos.x + 5, ent.pos.y + 5);
        ctx.fill();
        // Base
        ctx.fillStyle = COLORS.trophyBase;
        ctx.fillRect(ent.pos.x + 15, ent.pos.y + 25, 10, 5);
        ctx.fillRect(ent.pos.x + 10, ent.pos.y + 30, 20, 5);
        // Shine
        ctx.fillStyle = '#FFF';
        ctx.globalAlpha = 0.5;
        ctx.beginPath();
        ctx.arc(ent.pos.x + 15, ent.pos.y + 10, 3, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1.0;
      }
      else if (ent.type === EntityType.FLAG) {
         ctx.fillStyle = COLORS.gateLight || '#9CA3AF';
         ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         ctx.fillStyle = COLORS.gateDark || '#374151';
         ctx.beginPath();
         ctx.roundRect(ent.pos.x + 15, ent.pos.y + 20, ent.size.x - 30, ent.size.y - 20, 10);
         ctx.fill();
         ctx.strokeStyle = '#4B5563';
         ctx.lineWidth = 2;
         ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      }
      else if (ent.type === EntityType.ENEMY) {
         ctx.fillStyle = ent.color || COLORS.enemy;

         if (ent.enemyVariant === 'BAT') {
             // Draw Bat Wings
             ctx.fillStyle = ent.color || COLORS.enemyBat;
             ctx.beginPath();
             ctx.arc(ent.pos.x + 15, ent.pos.y + 10, 10, 0, Math.PI * 2); // Body
             ctx.fill();
             // Wings
             const wingFlap = Math.sin(Date.now() / 50) * 10;
             ctx.beginPath();
             ctx.moveTo(ent.pos.x + 5, ent.pos.y + 10);
             ctx.lineTo(ent.pos.x - 10, ent.pos.y + 5 + wingFlap);
             ctx.lineTo(ent.pos.x + 5, ent.pos.y + 15);
             ctx.fill();
             ctx.beginPath();
             ctx.moveTo(ent.pos.x + 25, ent.pos.y + 10);
             ctx.lineTo(ent.pos.x + 40, ent.pos.y + 5 + wingFlap);
             ctx.lineTo(ent.pos.x + 25, ent.pos.y + 15);
             ctx.fill();
         } else if (ent.enemyVariant === 'SLIME') {
             // Slime shape
             ctx.beginPath();
             ctx.arc(ent.pos.x + 15, ent.pos.y + 15, 15, Math.PI, 0); // Top
             ctx.lineTo(ent.pos.x + 30, ent.pos.y + 20);
             ctx.lineTo(ent.pos.x, ent.pos.y + 20);
             ctx.fill();
         } else {
             // Default Box
             ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         }

         // Eyes
         ctx.fillStyle = '#fff';
         const lookDir = ent.vel.x > 0 ? 1 : 0;
         if (ent.enemyVariant === 'BAT' || ent.enemyVariant === 'SLIME') {
             // Simple eyes
             ctx.fillRect(ent.pos.x + 10, ent.pos.y + 8, 4, 4);
             ctx.fillRect(ent.pos.x + 18, ent.pos.y + 8, 4, 4);
         } else {
             const eyeSize = ent.size.x * 0.2;
             ctx.fillRect(ent.pos.x + (lookDir ? ent.size.x * 0.6 : ent.size.x * 0.1), ent.pos.y + ent.size.y * 0.2, eyeSize, eyeSize);
             ctx.fillStyle = '#000';
             const pupilSize = eyeSize * 0.5;
             ctx.fillRect(ent.pos.x + (lookDir ? ent.size.x * 0.65 : ent.size.x * 0.15), ent.pos.y + ent.size.y * 0.25, pupilSize, pupilSize);
         }

         if (ent.enemyVariant === 'TANK' && ent.health && ent.maxHealth) {
             const hpPct = ent.health / ent.maxHealth;
             ctx.fillStyle = 'red';
             ctx.fillRect(ent.pos.x, ent.pos.y - 10, ent.size.x, 5);
             ctx.fillStyle = 'green';
             ctx.fillRect(ent.pos.x, ent.pos.y - 10, ent.size.x * hpPct, 5);
         }
      }
    });

    // 4. Draw Bullets
    ctx.fillStyle = COLORS.projectile;
    bullets.forEach(b => {
        ctx.beginPath();
        ctx.arc(b.pos.x + b.size.x/2, b.pos.y + b.size.y/2, b.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 5;
        ctx.shadowColor = 'white';
        ctx.fill();
        ctx.shadowBlur = 0;
    });

    // 5. Draw Player
    if (player.isInvulnerable && Math.floor(Date.now() / 100) % 2 === 0) {
       ctx.globalAlpha = 0.5;
    }

    ctx.fillStyle = COLORS.bear;
    ctx.beginPath();
    ctx.roundRect(player.pos.x, player.pos.y, player.size.x, player.size.y, 5);
    ctx.fill();

    ctx.beginPath();
    ctx.arc(player.pos.x + 5, player.pos.y + 2, 6, 0, Math.PI*2);
    ctx.arc(player.pos.x + player.size.x - 5, player.pos.y + 2, 6, 0, Math.PI*2);
    ctx.fill();

    // Drunk Face color change
    ctx.fillStyle = player.drunkTimer > 0 ? COLORS.bearFaceDrunk : COLORS.bearFace;
    const faceX = player.facingRight ? player.pos.x + 12 : player.pos.x + 2;
    ctx.beginPath();
    ctx.roundRect(faceX, player.pos.y + 8, 16, 12, 4);
    ctx.fill();

    ctx.fillStyle = '#000';
    const eyeOffsetX = player.facingRight ? 4 : 0;
    ctx.beginPath();
    ctx.arc(faceX + 4 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.arc(faceX + 10 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
    ctx.fill();

    ctx.beginPath();
    ctx.ellipse(faceX + 7 + eyeOffsetX, player.pos.y + 16, 3, 2, 0, 0, Math.PI*2);
    ctx.fill();

    ctx.fillStyle = COLORS.gun;
    const gunX = player.facingRight ? player.pos.x + 20 : player.pos.x - 5;
    const gunY = player.pos.y + 15;
    ctx.fillRect(gunX, gunY, 15, 6); // Barrel
    ctx.fillRect(player.facingRight ? gunX : gunX + 10, gunY + 2, 5, 8); // Handle

    ctx.globalAlpha = 1.0;
    ctx.restore();

    // 6. Draw Weather and Particles
    if (weather === 'RAIN') {
        ctx.strokeStyle = 'rgba(173, 216, 230, 0.6)';
        ctx.lineWidth = 2;
        particlesRef.current.forEach(p => {
            if (!p.color) { // Rain
                ctx.beginPath();
                ctx.moveTo(p.x, p.y);
                ctx.lineTo(p.x - 2, p.y + 10);
                ctx.stroke();
            }
        });
    } else if (weather === 'SNOW') {
        ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
        particlesRef.current.forEach(p => {
             if (!p.color) { // Snow
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                ctx.fill();
             }
        });
    } else if (weather === 'CAVE') {
        // Cave Drips
        ctx.fillStyle = '#737373';
        particlesRef.current.forEach(p => {
             if (p.color === '#525252') { 
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                ctx.fill();
             }
        });
    }

    // Draw Fire/Effect Particles (On top)
    particlesRef.current.forEach(p => {
        if (p.color && p.color !== '#525252') {
            ctx.fillStyle = p.color;
            ctx.globalAlpha = p.life;
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fill();
            ctx.globalAlpha = 1.0;
        }
    });
  };

  const loop = () => {
    update();
    draw();
    requestRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(loop);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [gameState.status]);

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      className="block bg-black rounded-lg shadow-2xl border-4 border-gray-700 mx-auto"
      style={{ maxWidth: '100%', maxHeight: '80vh', imageRendering: 'pixelated' }}
    />
  );
};

import React, { useState, useEffect } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameStatus, GameState } from './types';
import { levels } from './levels';
import { Heart, Coins, Trophy, Skull } from 'lucide-react';
import { MAX_HEALTH, REVIVE_COST } from './constants';
import { audio } from './audio';

const INITIAL_STATE: GameState = {
  status: GameStatus.MENU,
  currentLevelId: 1,
  score: 0,
  lives: MAX_HEALTH, // Acts as HP now
  coinsCollected: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(INITIAL_STATE);
  const [highScore, setHighScore] = useState(0);
  const [gameSessionId, setGameSessionId] = useState(0); // Used to force component remount

  useEffect(() => {
    const saved = localStorage.getItem('bear_adventure_highscore');
    if (saved) setHighScore(parseInt(saved));
  }, []);

  useEffect(() => {
    if (gameState.score > highScore) {
      setHighScore(gameState.score);
      localStorage.setItem('bear_adventure_highscore', gameState.score.toString());
    }
  }, [gameState.score, highScore]);

  const startGame = (levelId: number = 1) => {
    audio.init(); // Initialize audio context on user gesture
    setGameSessionId(prev => prev + 1); // Increment session ID to force fresh game instance
    setGameState({
      ...INITIAL_STATE,
      status: GameStatus.PLAYING,
      currentLevelId: levelId
    });
  };

  const handleLevelComplete = () => {
    // If last level, win game
    if (gameState.currentLevelId >= levels.length) {
       setGameState(prev => ({ ...prev, status: GameStatus.VICTORY }));
    } else {
       setGameState(prev => ({ ...prev, status: GameStatus.LEVEL_COMPLETE }));
    }
  };

  const handleNextLevel = () => {
    setGameState(prev => ({
      ...prev,
      status: GameStatus.PLAYING,
      currentLevelId: prev.currentLevelId + 1
    }));
  };

  const handlePlayerHit = () => {
     setGameState(prev => {
        const newLives = prev.lives - 1;
        if (newLives <= 0) {
            // Trigger Revive Prompt instead of immediate Game Over
            return { ...prev, lives: 0, status: GameStatus.REVIVE_PROMPT };
        }
        return { ...prev, lives: newLives };
     });
  };

  const handleRevive = () => {
    if (gameState.coinsCollected >= REVIVE_COST) {
        setGameState(prev => ({
            ...prev,
            lives: MAX_HEALTH,
            coinsCollected: prev.coinsCollected - REVIVE_COST,
            status: GameStatus.PLAYING
        }));
    }
  };

  const handleGiveUp = () => {
    // Standard Game Over - Reset level
    setGameState(prev => ({ ...prev, status: GameStatus.GAME_OVER }));
  };

  const currentLevel = levels.find(l => l.id === gameState.currentLevelId);

  return (
    <div className="min-h-screen bg-zinc-900 flex flex-col items-center justify-center p-4 font-sans select-none text-white">

      {/* Header / HUD */}
      <div className="w-full max-w-[800px] flex justify-between items-center mb-4 px-4 py-2 bg-zinc-800 rounded-xl border-2 border-zinc-700 shadow-lg">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 text-red-400">
            <Heart className="w-6 h-6 fill-current" />
            <span className="pixel-font text-xl">{gameState.lives}/{MAX_HEALTH}</span>
          </div>
          <div className="flex items-center gap-2 text-yellow-400">
            <Coins className="w-6 h-6 fill-current" />
            <span className="pixel-font text-xl">{gameState.coinsCollected}</span>
          </div>
        </div>

        <div className="text-center">
            <h1 className="text-sm text-gray-400 uppercase tracking-widest font-bold">{currentLevel?.name || "ADVENTURE"}</h1>
        </div>

        <div className="flex flex-col items-end">
          <span className="text-xs text-gray-400">分数 (SCORE)</span>
          <span className="pixel-font text-xl text-white">{gameState.score.toString().padStart(6, '0')}</span>
        </div>
      </div>

      {/* Main Game Area */}
      <div className="relative group">

        {/* Render Game Canvas */}
        {/* Use gameSessionId to force full reset on new game, but keep stable on revive */}
        <GameCanvas 
          key={`${gameState.currentLevelId}-${gameSessionId}`} 
          levelId={gameState.currentLevelId}
          gameState={gameState}
          setGameState={setGameState}
          onLevelComplete={handleLevelComplete}
          onPlayerHit={handlePlayerHit}
          onGameOver={() => setGameState(prev => ({ ...prev, lives: 0, status: GameStatus.REVIVE_PROMPT }))} 
        />

        {/* OVERLAYS */}

        {/* MENU */}
        {gameState.status === GameStatus.MENU && (
          <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center rounded-lg backdrop-blur-sm z-10">
            <h1 className="pixel-font text-5xl text-yellow-400 mb-2 drop-shadow-[0_4px_0_rgba(180,83,9,1)]">
              小熊大冒险
            </h1>
            <p className="text-gray-300 mb-8 max-w-md">帮助小熊收集金币，躲避愤怒的方块！</p>

            <div className="flex flex-col gap-4 items-center">
                <button 
                  onClick={() => startGame(1)}
                  className="bg-green-500 hover:bg-green-400 text-white border-b-4 border-green-700 font-bold py-3 px-8 rounded-lg transform active:translate-y-1 active:border-b-0 transition-all pixel-font text-lg"
                >
                  开始游戏
                </button>

                <div className="mt-4">
                  <p className="text-sm text-gray-400 mb-2">选择关卡:</p>
                  <div className="flex gap-2 flex-wrap justify-center max-w-md">
                    {levels.map((level) => (
                      <button 
                        key={level.id}
                        onClick={() => startGame(level.id)}
                        className="bg-zinc-700 hover:bg-zinc-600 text-white border-b-2 border-zinc-900 py-2 px-4 rounded text-xs pixel-font"
                      >
                        {level.id}. {level.name}
                      </button>
                    ))}
                  </div>
                </div>
            </div>
            <div className="mt-8 text-sm text-gray-500">
                <p>操作说明:</p>
                <div className="flex gap-4 mt-2 justify-center flex-wrap">
                    <span className="bg-zinc-700 px-2 py-1 rounded border border-zinc-600">← 向左移动</span>
                    <span className="bg-zinc-700 px-2 py-1 rounded border border-zinc-600">→ 向右移动</span>
                    <span className="bg-zinc-700 px-2 py-1 rounded border border-zinc-600">SPACE 跳跃</span>
                    <span className="bg-red-700 px-2 py-1 rounded border border-red-600 font-bold">F 射击</span>
                </div>
            </div>
          </div>
        )}

        {/* REVIVE PROMPT */}
        {gameState.status === GameStatus.REVIVE_PROMPT && (
          <div className="absolute inset-0 bg-red-900/90 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <Heart className="w-16 h-16 text-red-500 mb-4 animate-pulse" />
             <h2 className="pixel-font text-3xl text-white mb-4">你受伤了!</h2>
             <p className="text-white/80 mb-6">生命值已耗尽。</p>

             <div className="flex flex-col gap-4 w-64">
                <button 
                  onClick={handleRevive}
                  disabled={gameState.coinsCollected < REVIVE_COST}
                  className={`border-b-4 font-bold py-3 px-4 rounded-lg pixel-font transition-all ${
                    gameState.coinsCollected >= REVIVE_COST 
                    ? 'bg-yellow-400 text-yellow-900 hover:bg-yellow-300 border-yellow-600 cursor-pointer' 
                    : 'bg-gray-600 text-gray-400 border-gray-700 cursor-not-allowed opacity-50'
                  }`}
                >
                  原地复活 ({REVIVE_COST} 金币)
                </button>

                <button 
                  onClick={handleGiveUp}
                  className="bg-transparent border-2 border-white/20 text-white hover:bg-white/10 font-bold py-2 px-4 rounded-lg pixel-font text-sm"
                >
                  放弃 (重新开始)
                </button>
             </div>

             {gameState.coinsCollected < REVIVE_COST && (
                <p className="text-red-300 text-xs mt-2">金币不足!</p>
             )}
          </div>
        )}

        {/* GAME OVER */}
        {gameState.status === GameStatus.GAME_OVER && (
          <div className="absolute inset-0 bg-black/95 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <Skull className="w-16 h-16 text-gray-400 mb-4" />
             <h2 className="pixel-font text-4xl text-white mb-2">游戏结束</h2>
             <p className="text-white/80 mb-6">本次收集金币: {gameState.coinsCollected}</p>
             <button 
                  onClick={() => setGameState(INITIAL_STATE)}
                  className="bg-white text-black hover:bg-gray-200 border-b-4 border-gray-400 font-bold py-3 px-8 rounded-lg pixel-font"
                >
                  返回标题
             </button>
          </div>
        )}

        {/* LEVEL COMPLETE */}
        {gameState.status === GameStatus.LEVEL_COMPLETE && (
          <div className="absolute inset-0 bg-blue-900/90 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <Trophy className="w-16 h-16 text-yellow-400 mb-4 animate-pulse" />
             <h2 className="pixel-font text-4xl text-white mb-2">关卡完成!</h2>
             <p className="text-white/80 mb-6">准备好迎接下一个挑战了吗?</p>
             <button 
                  onClick={handleNextLevel}
                  className="bg-yellow-400 text-yellow-900 hover:bg-yellow-300 border-b-4 border-yellow-600 font-bold py-3 px-8 rounded-lg pixel-font"
                >
                  下一关
             </button>
          </div>
        )}

        {/* VICTORY */}
        {gameState.status === GameStatus.VICTORY && (
          <div className="absolute inset-0 bg-yellow-500/95 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <div className="text-6xl mb-4">👑</div>
             <h2 className="pixel-font text-5xl text-white mb-4 drop-shadow-md">胜利!</h2>
